pub use yggterm_core::SessionKind;

fn live_session_default_title(kind: SessionKind, cwd: Option<&str>, fallback: &str) -> String {
    match kind {
        SessionKind::Shell | SessionKind::SshShell => cwd
            .map(str::trim)
            .filter(|value| !value.is_empty())
            .map(ToOwned::to_owned)
            .unwrap_or_else(|| fallback.to_string()),
        _ => fallback.to_string(),
    }
}

fn live_session_default_summary(kind: SessionKind, target: &SshConnectTarget) -> String {
    let cwd = target
        .cwd
        .as_deref()
        .filter(|value| !value.trim().is_empty());
    match kind {
        SessionKind::SshShell => match cwd {
            Some(cwd) => format!(
                "Remote shell rooted at {cwd} on {}; use it for direct command-line work while Yggterm preserves the daemon-owned PTY.",
                target.ssh_target
            ),
            None => format!(
                "Remote shell on {}; use it for direct command-line work while Yggterm preserves the daemon-owned PTY.",
                target.ssh_target
            ),
        },
        SessionKind::Shell => match cwd {
            Some(cwd) => format!(
                "Interactive shell rooted at {cwd}; use it for command-line work while Yggterm keeps the PTY available across sidebar navigation."
            ),
            None => {
                "Interactive shell for command-line work while Yggterm keeps the PTY available across sidebar navigation.".to_string()
            }
        },
        SessionKind::Codex => match cwd {
            Some(cwd) => format!(
                "Codex session rooted at {cwd}; the daemon owns the PTY so the conversation can survive sidebar navigation and GUI restarts."
            ),
            None => {
                "Codex session with daemon-owned PTY state so the conversation can survive sidebar navigation and GUI restarts.".to_string()
            }
        },
        SessionKind::CodexLiteLlm => match cwd {
            Some(cwd) => format!(
                "Codex LiteLLM session rooted at {cwd}; the daemon owns the PTY so the conversation can survive sidebar navigation and GUI restarts."
            ),
            None => {
                "Codex LiteLLM session with daemon-owned PTY state so the conversation can survive sidebar navigation and GUI restarts.".to_string()
            }
        },
        SessionKind::ClaudeCode => match cwd {
            Some(cwd) => format!(
                "Claude Code session rooted at {cwd}; the daemon owns the PTY so the conversation can survive sidebar navigation and GUI restarts."
            ),
            None => {
                "Claude Code session with daemon-owned PTY state so the conversation can survive sidebar navigation and GUI restarts.".to_string()
            }
        },
        SessionKind::Document => "Document preview.".to_string(),
    }
}

fn live_local_source_metadata_value(kind: SessionKind) -> &'static str {
    match kind {
        SessionKind::Shell => "local-shell",
        SessionKind::Codex => "local-codex",
        SessionKind::CodexLiteLlm => "local-codex-litellm",
        SessionKind::ClaudeCode => "local-claude-code",
        SessionKind::SshShell => "live-ssh",
        SessionKind::Document => "document",
    }
}

fn live_local_target_metadata_value(kind: SessionKind, cwd: &str) -> String {
    match kind {
        SessionKind::Shell
        | SessionKind::Codex
        | SessionKind::CodexLiteLlm
        | SessionKind::ClaudeCode => cwd.to_string(),
        SessionKind::SshShell => "remote".to_string(),
        SessionKind::Document => "document".to_string(),
    }
}

fn live_local_prefix_metadata_value(kind: SessionKind) -> &'static str {
    match kind {
        SessionKind::Shell => "shell",
        SessionKind::Codex => "codex",
        SessionKind::CodexLiteLlm => "codex-litellm",
        SessionKind::ClaudeCode => "claude",
        SessionKind::SshShell => "none",
        SessionKind::Document => "none",
    }
}

fn is_remote_scanned_live_session_path(path: &str) -> bool {
    path.starts_with("remote-session://")
}

fn local_live_session_kind_is_recoverable(kind: SessionKind) -> bool {
    matches!(
        kind,
        SessionKind::Shell
            | SessionKind::Codex
            | SessionKind::CodexLiteLlm
            | SessionKind::ClaudeCode
    )
}

fn persisted_live_session_is_recoverable(live: &PersistedLiveSession) -> bool {
    // remote-cc:// is the Claude Code twin of remote-session:// — both are
    // first-class remote agent sessions ([[spec-unify-local-remote]]). Only
    // recognizing the codex scheme here dropped every remote CC keep-alive
    // session at daemon restart (fell through to the SshShell-only arm;
    // live-caught 2026-06-10: all CC sessions gone after the 2.8.73 swap).
    if parse_remote_scanned_session_path(&live.key).is_some()
        || parse_remote_cc_session_path(&live.key).is_some()
    {
        return !is_loopback_ssh_target(&live.ssh_target);
    }
    if is_local_codex_storage_session_path(&live.key)
        || live
            .storage_path
            .as_deref()
            .is_some_and(is_local_codex_storage_session_path)
    {
        return is_loopback_ssh_target(&live.ssh_target)
            && local_live_session_kind_is_recoverable(live.kind);
    }
    if is_loopback_ssh_target(&live.ssh_target) {
        return local_live_session_kind_is_recoverable(live.kind);
    }
    live.kind == SessionKind::SshShell && !is_loopback_ssh_target(&live.ssh_target)
}

fn managed_live_session_is_recoverable(key: &str, session: &ManagedSessionView) -> bool {
    if is_local_codex_storage_session_path(key)
        || is_local_codex_storage_session_path(&session.session_path)
    {
        return false;
    }
    // remote-cc:// twin of remote-session:// — see persisted_live_session_is_recoverable.
    if parse_remote_scanned_session_path(key).is_some()
        || parse_remote_cc_session_path(key).is_some()
    {
        return session
            .ssh_target
            .as_deref()
            .is_some_and(|target| !is_loopback_ssh_target(target));
    }
    // A row holding a LOCAL live runtime key (local:// / codex-runtime://) is
    // a live runtime session regardless of its `source` — recovery-created
    // rows (opened from their CLI JSONL) carry source=Stored, and requiring
    // LiveLocal here silently dropped them from persistence at every swap
    // (2.8.79 live incident: the roundtrip test passed with LiveLocal while
    // the recovered live rows kept vanishing). The iteration source is
    // live_session_order, so a local-keyed entry here is by construction a
    // live row.
    if session.source == SessionSource::LiveLocal || local_runtime_id_from_key(key).is_some() {
        return local_live_session_kind_is_recoverable(session.kind);
    }
    session.kind == SessionKind::SshShell
        && session
            .ssh_target
            .as_deref()
            .is_some_and(|target| !is_loopback_ssh_target(target))
}

const RUNTIME_PERSISTENCE_METADATA_LABEL: &str = "Runtime Persistence";
const RUNTIME_PERSISTENCE_KEEP_ALIVE: &str = "keep-alive";
const UPDATE_RESTART_RESTORE_REASON: &str = "update-restart";
const RUNTIME_RESTORE_REASON_METADATA_LABEL: &str = "Runtime Restore Reason";
const REMOTE_LAUNCH_ACTION_METADATA_LABEL: &str = "Remote Launch Action";

fn session_keep_alive(session: &ManagedSessionView) -> bool {
    session
        .metadata
        .iter()
        .find(|entry| entry.label == RUNTIME_PERSISTENCE_METADATA_LABEL)
        .is_some_and(|entry| entry.value == RUNTIME_PERSISTENCE_KEEP_ALIVE)
}

fn set_session_keep_alive_metadata(session: &mut ManagedSessionView, keep_alive: bool) {
    if keep_alive {
        upsert_session_metadata(
            &mut session.metadata,
            "Runtime Persistence",
            RUNTIME_PERSISTENCE_KEEP_ALIVE.to_string(),
        );
    } else {
        session
            .metadata
            .retain(|entry| entry.label != RUNTIME_PERSISTENCE_METADATA_LABEL);
    }
}

fn persisted_live_session_from_managed(
    key: &str,
    session: &ManagedSessionView,
    keep_alive: bool,
    restore_reason: Option<String>,
    protect_for_update_restart: bool,
) -> Option<PersistedLiveSession> {
    let has_promoted_codex_identity = session.kind == SessionKind::Codex
        && session_metadata_value(session, "Codex Session")
            .as_deref()
            .is_some_and(|session_id| !session_id.trim().is_empty());
    let remote_launch_action = session_metadata_value(session, REMOTE_LAUNCH_ACTION_METADATA_LABEL)
        .filter(|action| {
            !(action.as_str() == "start-codex"
                && (protect_for_update_restart || has_promoted_codex_identity))
        });
    let storage_path = session_metadata_value(session, "Storage");
    // LOGICAL-BLUNDER FIX (user-named, 2026-06-11): LOCAL live sessions have
    // no ssh_target, so this mapper silently dropped them from persistence —
    // their identity (row, title, UUID→Storage link) lived ONLY in daemon
    // memory and died with every daemon swap, even though the CLI transcript
    // is durable on disk (live-caught: home/pi codex 019e9c28 + litellm both
    // vanished at the 2.8.78 swap). The restore path already handles loopback
    // entries (canonical local key + local resume), so persist locals with
    // the loopback target. Agent kinds restore faithfully via their Storage
    // JSONL; a not-yet-rebound row (no Storage) still keeps its row + title.
    let ssh_target = session.ssh_target.clone().or_else(|| {
        (session.source == SessionSource::LiveLocal
            && local_live_session_kind_is_recoverable(session.kind))
        .then(|| "localhost".to_string())
    });
    ssh_target.map(|ssh_target| PersistedLiveSession {
        key: key.to_string(),
        id: session.id.clone(),
        title: session.title.clone(),
        kind: session.kind,
        keep_alive,
        ssh_target,
        prefix: session.ssh_prefix.clone(),
        cwd: session
            .metadata
            .iter()
            .find(|entry| entry.label == "Cwd")
            .map(|entry| entry.value.clone()),
        remote_launch_action,
        storage_path,
        restore_reason,
    })
}

fn passive_title_hint_can_update(current_title: &str, title_hint: &str, was_missing: bool) -> bool {
    let hint = title_hint.trim();
    if hint.is_empty() || looks_like_generated_fallback_title(hint) {
        return false;
    }
    let current = current_title.trim();
    was_missing
        || current.is_empty()
        || looks_like_generated_fallback_title(current)
        || matches!(
            current.to_ascii_lowercase().as_str(),
            "preview" | "session" | "terminal"
        )
}

fn is_local_claude_code_storage_session_path(path: &str) -> bool {
    path.contains("/.claude/projects/") && path.ends_with(".jsonl")
}

fn is_local_codex_storage_session_path(path: &str) -> bool {
    path.contains("/.codex/sessions/") || path.contains("/.codex-litellm/sessions/")
}

fn normalize_proc_fd_target_path(path: &Path) -> Option<PathBuf> {
    let raw = path.to_string_lossy();
    let trimmed = raw
        .strip_suffix(" (deleted)")
        .unwrap_or(raw.as_ref())
        .trim();
    if !is_local_codex_storage_session_path(trimmed) {
        return None;
    }
    let normalized = PathBuf::from(trimmed);
    (normalized.extension().and_then(|ext| ext.to_str()) == Some("jsonl")).then_some(normalized)
}

/// Per AGENTS.md "saved-session identity should use the real Codex session id
/// from the open transcript when available." Same applies to Claude Code:
/// when a `claude` process is running with `~/.claude/projects/<encoded-cwd>/
/// <session-id>.jsonl` open, the basename IS the real Claude Code session
/// identity. Walking the process tree FDs lets us discover that ID and rebind
/// the live-session row away from the synthetic UUIDv4 that
/// `start_local_session` allocated.
fn normalize_proc_fd_target_path_for_claude_code(path: &Path) -> Option<PathBuf> {
    let raw = path.to_string_lossy();
    let trimmed = raw
        .strip_suffix(" (deleted)")
        .unwrap_or(raw.as_ref())
        .trim();
    if !is_local_claude_code_storage_session_path(trimmed) {
        return None;
    }
    Some(PathBuf::from(trimmed))
}

#[cfg(target_os = "linux")]
fn normalize_proc_fd_target_for_storage(path: &Path) -> Option<PathBuf> {
    let raw = path.to_string_lossy();
    let trimmed = raw
        .strip_suffix(" (deleted)")
        .unwrap_or(raw.as_ref())
        .trim();
    (!trimmed.is_empty()).then(|| PathBuf::from(trimmed))
}

#[cfg(target_os = "linux")]
#[derive(Debug, Clone)]
struct CodexSqliteStoragePaths {
    logs_paths: Vec<PathBuf>,
    state_paths: Vec<PathBuf>,
}

#[cfg(target_os = "linux")]
fn proc_fd_path_is_codex_sqlite(path: &Path, prefix: &str) -> bool {
    let Some(parent_name) = path
        .parent()
        .and_then(|parent| parent.file_name())
        .and_then(|name| name.to_str())
    else {
        return false;
    };
    if !matches!(parent_name, ".codex" | ".codex-litellm") {
        return false;
    }
    path.file_name()
        .and_then(|name| name.to_str())
        .is_some_and(|name| name.starts_with(prefix) && name.ends_with(".sqlite"))
}

#[cfg(target_os = "linux")]
fn codex_sqlite_paths_from_process_fds(pid: u32) -> Option<CodexSqliteStoragePaths> {
    let Ok(entries) = fs::read_dir(format!("/proc/{pid}/fd")) else {
        return None;
    };
    let mut logs_paths = Vec::new();
    let mut state_paths = Vec::new();
    for target in entries
        .flatten()
        .filter_map(|entry| fs::read_link(entry.path()).ok())
        .filter_map(|target| normalize_proc_fd_target_for_storage(&target))
    {
        if proc_fd_path_is_codex_sqlite(&target, "logs_") {
            logs_paths.push(target);
        } else if proc_fd_path_is_codex_sqlite(&target, "state_") {
            state_paths.push(target);
        }
    }
    logs_paths.sort();
    state_paths.sort();
    if logs_paths.is_empty() {
        return None;
    }
    Some(CodexSqliteStoragePaths {
        logs_paths,
        state_paths,
    })
}

#[cfg(target_os = "linux")]
fn codex_sqlite_state_path_candidates(
    logs_paths: &[PathBuf],
    explicit_state_paths: &[PathBuf],
) -> Vec<PathBuf> {
    let mut seen = HashSet::new();
    let mut candidates = Vec::new();
    for path in explicit_state_paths {
        if seen.insert(path.clone()) {
            candidates.push(path.clone());
        }
    }
    for logs_path in logs_paths {
        let Some(parent) = logs_path.parent() else {
            continue;
        };
        let Ok(entries) = fs::read_dir(parent) else {
            continue;
        };
        for entry in entries.flatten() {
            let path = entry.path();
            if proc_fd_path_is_codex_sqlite(&path, "state_") && seen.insert(path.clone()) {
                candidates.push(path);
            }
        }
    }
    candidates.sort();
    candidates
}

#[cfg(target_os = "linux")]
fn open_readonly_sqlite(path: &Path) -> Option<Connection> {
    Connection::open_with_flags(path, OpenFlags::SQLITE_OPEN_READ_ONLY).ok()
}

#[cfg(target_os = "linux")]
fn codex_thread_id_from_recent_logs(logs_path: &Path, pid: u32) -> Option<String> {
    let conn = open_readonly_sqlite(logs_path)?;
    let process_pattern = format!("pid:{pid}:%");
    conn.query_row(
        "SELECT thread_id \
         FROM (SELECT id, thread_id, process_uuid FROM logs ORDER BY id DESC LIMIT 20000) \
         WHERE process_uuid LIKE ?1 AND thread_id IS NOT NULL AND thread_id <> '' \
         ORDER BY id DESC LIMIT 1",
        params![process_pattern],
        |row| row.get::<_, String>(0),
    )
    .optional()
    .ok()
    .flatten()
}

#[cfg(target_os = "linux")]
fn codex_thread_identity_from_state(
    state_path: &Path,
    thread_id: &str,
) -> Option<CodexRuntimeProcessIdentity> {
    let conn = open_readonly_sqlite(state_path)?;
    let (rollout_path, cwd): (String, String) = conn
        .query_row(
            "SELECT rollout_path, cwd FROM threads WHERE id = ?1 LIMIT 1",
            params![thread_id],
            |row| Ok((row.get(0)?, row.get(1)?)),
        )
        .optional()
        .ok()
        .flatten()?;
    let storage_path = PathBuf::from(rollout_path.trim());
    if storage_path.as_os_str().is_empty() {
        return None;
    }
    Some(CodexRuntimeProcessIdentity {
        storage_path,
        session_id: thread_id.to_string(),
        cwd,
    })
}

#[cfg(target_os = "linux")]
fn codex_sqlite_process_identity_from_pid(pid: u32) -> Option<CodexRuntimeProcessIdentity> {
    let paths = codex_sqlite_paths_from_process_fds(pid)?;
    codex_sqlite_process_identity_from_paths(&paths.logs_paths, &paths.state_paths, pid)
}

#[cfg(target_os = "linux")]
fn codex_sqlite_process_identity_from_paths(
    logs_paths: &[PathBuf],
    state_paths: &[PathBuf],
    pid: u32,
) -> Option<CodexRuntimeProcessIdentity> {
    let state_candidates = codex_sqlite_state_path_candidates(logs_paths, state_paths);
    for logs_path in logs_paths {
        let Some(thread_id) = codex_thread_id_from_recent_logs(logs_path, pid) else {
            continue;
        };
        for state_path in &state_candidates {
            if let Some(identity) = codex_thread_identity_from_state(state_path, &thread_id) {
                return Some(identity);
            }
        }
    }
    None
}

#[cfg(target_os = "linux")]
fn linux_proc_child_pids(parent_pid: u32) -> Vec<u32> {
    let Ok(entries) = fs::read_dir("/proc") else {
        return Vec::new();
    };
    let mut children = Vec::new();
    for entry in entries.flatten() {
        let file_name = entry.file_name();
        let Some(pid) = file_name
            .to_str()
            .and_then(|value| value.parse::<u32>().ok())
        else {
            continue;
        };
        let Ok(status) = fs::read_to_string(entry.path().join("status")) else {
            continue;
        };
        let Some(ppid) = status.lines().find_map(|line| {
            line.strip_prefix("PPid:")
                .and_then(|value| value.trim().parse::<u32>().ok())
        }) else {
            continue;
        };
        if ppid == parent_pid {
            children.push(pid);
        }
    }
    children
}

#[cfg(target_os = "linux")]
fn linux_proc_cmdline_args(pid: u32) -> Option<Vec<String>> {
    let bytes = fs::read(format!("/proc/{pid}/cmdline")).ok()?;
    if bytes.is_empty() {
        return None;
    }
    let args = bytes
        .split(|byte| *byte == 0)
        .filter(|part| !part.is_empty())
        .map(|part| String::from_utf8_lossy(part).to_string())
        .collect::<Vec<_>>();
    (!args.is_empty()).then_some(args)
}

#[cfg(target_os = "linux")]
fn linux_proc_parent_pid(pid: u32) -> Option<u32> {
    let status = fs::read_to_string(format!("/proc/{pid}/status")).ok()?;
    status.lines().find_map(|line| {
        line.strip_prefix("PPid:")
            .and_then(|value| value.trim().parse::<u32>().ok())
    })
}

#[cfg(target_os = "linux")]
fn linux_proc_state(pid: u32) -> Option<char> {
    let status = fs::read_to_string(format!("/proc/{pid}/status")).ok()?;
    status
        .lines()
        .find_map(|line| line.strip_prefix("State:"))
        .and_then(|value| value.trim().chars().next())
}

fn command_arg_basename(arg: &str) -> &str {
    arg.rsplit(['/', '\\'])
        .next()
        .filter(|value| !value.is_empty())
        .unwrap_or(arg)
}

fn command_arg_is_codex_binary(arg: &str) -> bool {
    matches!(
        command_arg_basename(arg),
        "codex" | "codex.exe" | "codex.cmd"
    )
}

#[cfg(target_os = "linux")]
fn codex_resume_args_match_session(args: &[String], session_id: &str) -> bool {
    args.iter()
        .take(3)
        .any(|arg| command_arg_is_codex_binary(arg))
        && args.iter().any(|arg| arg == "resume")
        && args.iter().any(|arg| arg == session_id)
}

#[cfg(target_os = "linux")]
fn yggterm_process_args(args: &[String]) -> bool {
    let Some(argv0) = args.first() else {
        return false;
    };
    matches!(
        command_arg_basename(argv0),
        "yggterm" | "yggterm-headless" | "yggterm.exe" | "yggterm-headless.exe"
    ) || args.windows(3).any(|window| {
        window[0] == "server"
            && window[1] == "remote"
            && matches!(window[2].as_str(), "resume-codex" | "start-codex")
    })
}

#[cfg(target_os = "linux")]
fn codex_resume_process_is_external_for_session(
    args: &[String],
    ancestor_args: &[Vec<String>],
    session_id: &str,
) -> bool {
    codex_resume_args_match_session(args, session_id)
        && !ancestor_args
            .iter()
            .any(|ancestor| yggterm_process_args(ancestor))
}

#[cfg(target_os = "linux")]
fn linux_proc_ancestor_cmdline_args(pid: u32) -> Vec<Vec<String>> {
    let mut ancestors = Vec::new();
    let mut seen = HashSet::new();
    let mut current = linux_proc_parent_pid(pid);
    while let Some(parent_pid) = current {
        if parent_pid == 0 || !seen.insert(parent_pid) {
            break;
        }
        if let Some(args) = linux_proc_cmdline_args(parent_pid) {
            ancestors.push(args);
        }
        current = linux_proc_parent_pid(parent_pid);
    }
    ancestors
}

#[cfg(target_os = "linux")]
#[derive(Debug, Clone, PartialEq, Eq)]
struct ExternalCodexResumeProcess {
    pid: u32,
    argv0: String,
}

#[cfg(target_os = "linux")]
fn external_codex_resume_processes_for_session(
    session_id: &str,
) -> Vec<ExternalCodexResumeProcess> {
    let Ok(entries) = fs::read_dir("/proc") else {
        return Vec::new();
    };
    let current_pid = std::process::id();
    let mut processes = entries
        .flatten()
        .filter_map(|entry| entry.file_name().to_str()?.parse::<u32>().ok())
        .filter(|pid| *pid != current_pid)
        .filter(|pid| linux_proc_state(*pid) != Some('Z'))
        .filter_map(|pid| {
            let args = linux_proc_cmdline_args(pid)?;
            if !codex_resume_args_match_session(&args, session_id) {
                return None;
            }
            let ancestor_args = linux_proc_ancestor_cmdline_args(pid);
            codex_resume_process_is_external_for_session(&args, &ancestor_args, session_id).then(
                || ExternalCodexResumeProcess {
                    pid,
                    argv0: args.first().cloned().unwrap_or_default(),
                },
            )
        })
        .collect::<Vec<_>>();
    processes.sort_by_key(|process| process.pid);
    processes.dedup_by_key(|process| process.pid);
    processes
}

#[cfg(not(target_os = "linux"))]
#[derive(Debug, Clone, PartialEq, Eq)]
struct ExternalCodexResumeProcess {
    pid: u32,
    argv0: String,
}

#[cfg(not(target_os = "linux"))]
fn external_codex_resume_processes_for_session(
    _session_id: &str,
) -> Vec<ExternalCodexResumeProcess> {
    Vec::new()
}

fn remote_resume_external_active_message(
    session_id: &str,
    processes: &[ExternalCodexResumeProcess],
) -> String {
    let pids = processes
        .iter()
        .map(|process| process.pid.to_string())
        .collect::<Vec<_>>()
        .join(", ");
    format!(
        "yggterm: Codex session {session_id} is already active outside Yggterm (pid {pids}); waiting instead of starting a second resume. Close that external terminal to let Yggterm attach."
    )
}

fn remote_resume_snapshot_is_external_active_guard(bytes: &[u8]) -> bool {
    let normalized = String::from_utf8_lossy(bytes).to_ascii_lowercase();
    normalized.contains("yggterm:")
        && normalized.contains("already active outside yggterm")
        && normalized.contains("waiting instead of starting a second resume")
}

fn wait_for_external_codex_resume_to_clear(home: &Path, session_id: &str) {
    let mut announced = false;
    let mut last_pids = Vec::<u32>::new();
    loop {
        let processes = external_codex_resume_processes_for_session(session_id);
        if processes.is_empty() {
            if announced {
                append_trace_event(
                    home,
                    "remote",
                    "resume_codex",
                    "external_active_wait_end",
                    json!({ "session_id": session_id }),
                );
            }
            return;
        }
        let pids = processes
            .iter()
            .map(|process| process.pid)
            .collect::<Vec<_>>();
        if !announced || pids != last_pids {
            append_trace_event(
                home,
                "remote",
                "resume_codex",
                "external_active_wait",
                json!({
                    "session_id": session_id,
                    "pids": pids,
                    "argv0": processes.iter().map(|process| process.argv0.clone()).collect::<Vec<_>>(),
                    "policy": "session_survival_before_yggterm_attach",
                }),
            );
            println!(
                "{}",
                remote_resume_external_active_message(session_id, &processes)
            );
            let _ = std::io::stdout().flush();
            announced = true;
            last_pids = processes
                .iter()
                .map(|process| process.pid)
                .collect::<Vec<_>>();
        }
        std::thread::sleep(Duration::from_millis(3_000));
    }
}

#[cfg(target_os = "linux")]
fn remote_codex_bridge_args_match(args: &[String], session_id: &str) -> bool {
    args.windows(4).any(|window| {
        window[0] == "server"
            && window[1] == "remote"
            && matches!(window[2].as_str(), "resume-codex" | "start-codex")
            && window[3] == session_id
    })
}

#[cfg(target_os = "linux")]
fn linux_remote_codex_bridge_pids_for_session(session_id: &str) -> Vec<u32> {
    let Ok(entries) = fs::read_dir("/proc") else {
        return Vec::new();
    };
    let current_pid = std::process::id();
    let mut pids = entries
        .flatten()
        .filter_map(|entry| entry.file_name().to_str()?.parse::<u32>().ok())
        .filter(|pid| *pid != current_pid)
        .filter(|pid| {
            linux_proc_cmdline_args(*pid)
                .as_deref()
                .is_some_and(|args| remote_codex_bridge_args_match(args, session_id))
        })
        .collect::<Vec<_>>();
    pids.sort_unstable();
    pids.dedup();
    pids
}

#[cfg(target_os = "linux")]
fn linux_proc_descendant_pids(root_pid: u32) -> Vec<u32> {
    let mut queue = VecDeque::from([root_pid]);
    let mut descendants = Vec::new();
    let mut seen = HashSet::new();
    while let Some(pid) = queue.pop_front() {
        if !seen.insert(pid) {
            continue;
        }
        for child in linux_proc_child_pids(pid) {
            descendants.push(child);
            queue.push_back(child);
        }
    }
    descendants
}

#[cfg(target_os = "linux")]
fn linux_proc_process_exists(pid: u32) -> bool {
    Path::new("/proc").join(pid.to_string()).exists()
}

#[cfg(target_os = "linux")]
fn linux_kill_pid(pid: u32, signal: libc::c_int) {
    unsafe {
        libc::kill(pid as libc::pid_t, signal);
    }
}

#[cfg(target_os = "linux")]
fn terminate_linux_process_tree(root_pid: u32) {
    let mut pids = linux_proc_descendant_pids(root_pid);
    pids.push(root_pid);
    pids.sort_unstable();
    pids.dedup();
    for pid in pids.iter().rev() {
        linux_kill_pid(*pid, libc::SIGTERM);
    }
    let deadline = Instant::now() + Duration::from_secs(2);
    while Instant::now() < deadline && pids.iter().any(|pid| linux_proc_process_exists(*pid)) {
        std::thread::sleep(Duration::from_millis(50));
    }
    for pid in pids.iter().rev() {
        if linux_proc_process_exists(*pid) {
            linux_kill_pid(*pid, libc::SIGKILL);
        }
    }
}

#[cfg(target_os = "linux")]
fn terminate_remote_codex_bridge_processes(session_id: &str) -> usize {
    let pids = linux_remote_codex_bridge_pids_for_session(session_id);
    for pid in &pids {
        terminate_linux_process_tree(*pid);
    }
    pids.len()
}

#[cfg(not(target_os = "linux"))]
fn terminate_remote_codex_bridge_processes(_session_id: &str) -> usize {
    0
}

#[cfg(target_os = "linux")]
fn codex_storage_path_from_process_fds(pid: u32) -> Option<PathBuf> {
    let Ok(entries) = fs::read_dir(format!("/proc/{pid}/fd")) else {
        return None;
    };
    let mut candidates = entries
        .flatten()
        .filter_map(|entry| fs::read_link(entry.path()).ok())
        .filter_map(|target| normalize_proc_fd_target_path(&target))
        .collect::<Vec<_>>();
    candidates.sort();
    candidates.into_iter().next()
}

fn claude_code_storage_path_from_process_fds(pid: u32) -> Option<PathBuf> {
    let Ok(entries) = fs::read_dir(format!("/proc/{pid}/fd")) else {
        return None;
    };
    let mut candidates = entries
        .flatten()
        .filter_map(|entry| fs::read_link(entry.path()).ok())
        .filter_map(|target| normalize_proc_fd_target_path_for_claude_code(&target))
        .collect::<Vec<_>>();
    candidates.sort();
    candidates.into_iter().next()
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub(crate) struct CodexRuntimeProcessIdentity {
    pub storage_path: PathBuf,
    pub session_id: String,
    pub cwd: String,
}

/// Mirrors `CodexRuntimeProcessIdentity` for Claude Code. AGENTS.md spec
/// "saved-session identity should use the real Codex session id from the
/// open transcript when available" — same principle for Claude Code:
/// the basename of the open `~/.claude/projects/<encoded-cwd>/<id>.jsonl`
/// IS the real Claude Code session id.
#[derive(Debug, Clone, PartialEq, Eq)]
pub(crate) struct ClaudeCodeRuntimeProcessIdentity {
    pub storage_path: PathBuf,
    pub session_id: String,
    pub cwd: String,
}

#[cfg(target_os = "linux")]
pub(crate) fn claude_code_runtime_process_identity_from_root_pid(
    root_pid: u32,
) -> Option<ClaudeCodeRuntimeProcessIdentity> {
    let mut queue = VecDeque::from([root_pid]);
    let mut seen = HashSet::new();
    while let Some(pid) = queue.pop_front() {
        if !seen.insert(pid) {
            continue;
        }
        if let Some(storage_path) = claude_code_storage_path_from_process_fds(pid)
            && let Ok(Some((session_id, cwd))) = read_cc_session_identity_fields(&storage_path)
        {
            return Some(ClaudeCodeRuntimeProcessIdentity {
                storage_path,
                session_id,
                cwd,
            });
        }
        queue.extend(linux_proc_child_pids(pid));
    }
    None
}

#[cfg(not(target_os = "linux"))]
pub(crate) fn claude_code_runtime_process_identity_from_root_pid(
    _root_pid: u32,
) -> Option<ClaudeCodeRuntimeProcessIdentity> {
    None
}

#[cfg(target_os = "linux")]
pub(crate) fn codex_runtime_process_identity_from_root_pid(
    root_pid: u32,
) -> Option<CodexRuntimeProcessIdentity> {
    let mut queue = VecDeque::from([root_pid]);
    let mut seen = HashSet::new();
    while let Some(pid) = queue.pop_front() {
        if !seen.insert(pid) {
            continue;
        }
        if let Some(storage_path) = codex_storage_path_from_process_fds(pid)
            && let Ok(Some((session_id, cwd))) = read_codex_session_identity_fields(&storage_path)
        {
            return Some(CodexRuntimeProcessIdentity {
                storage_path,
                session_id,
                cwd,
            });
        }
        if let Some(identity) = codex_sqlite_process_identity_from_pid(pid) {
            return Some(identity);
        }
        queue.extend(linux_proc_child_pids(pid));
    }
    None
}

