pub(crate) fn codex_runtime_process_identity_from_root_pid(
    _root_pid: u32,
) -> Option<CodexRuntimeProcessIdentity> {
    None
}

fn upsert_snapshot_metadata(metadata: &mut Vec<SnapshotMetadataEntry>, label: &str, value: String) {
    if let Some(entry) = metadata.iter_mut().find(|entry| entry.label == label) {
        entry.value = value;
    } else {
        metadata.push(SnapshotMetadataEntry {
            label: label.to_string(),
            value,
        });
    }
}

/// #16: cold attach resumes via the STORED `launch_command`, which embeds the
/// session id (e.g. `... resume-codex <id> ...`). At spawn that id is the
/// synthesized UUIDv4; a runtime-identity rebind later learns the real CLI id.
/// Re-point the stored launch_command at the real id so a cold attach resumes
/// the actual transcript instead of the dead UUIDv4 (which failed until a
/// close+reopen rebuilt the command). No-op when the id isn't embedded (e.g.
/// a bare `codex` / `claude` start command). See
/// finding-codex-cold-attach-stale-launch-command.
fn repoint_stored_launch_command_session_id(session: &mut ManagedSessionView, new_id: &str) {
    let previous_id = session.id.clone();
    if !previous_id.trim().is_empty()
        && previous_id != new_id
        && session.launch_command.contains(&previous_id)
    {
        session.launch_command = session.launch_command.replace(&previous_id, new_id);
    }
}

pub(crate) fn overlay_codex_runtime_snapshot_identity(
    session: &mut SnapshotSessionView,
    identity: &CodexRuntimeProcessIdentity,
    yggterm_home: Option<&Path>,
) {
    if session.kind != SessionKind::Codex {
        return;
    }
    let runtime_key = session.session_path.clone();
    let title_was_generated = session.title.trim().is_empty()
        || looks_like_generated_fallback_title(&session.title)
        || parse_remote_runtime_codex_session_key(&runtime_key)
            .is_some_and(|runtime_id| session.title.contains(runtime_id));
    session.id = identity.session_id.clone();
    upsert_snapshot_metadata(
        &mut session.metadata,
        "Storage",
        identity.storage_path.display().to_string(),
    );
    upsert_snapshot_metadata(
        &mut session.metadata,
        "Codex Session",
        identity.session_id.clone(),
    );
    upsert_snapshot_metadata(&mut session.metadata, "Runtime Session", runtime_key);
    if !identity.cwd.trim().is_empty() {
        upsert_snapshot_metadata(&mut session.metadata, "Cwd", identity.cwd.clone());
    }
    if title_was_generated {
        let title = yggterm_home
            .and_then(|home| SessionTitleStore::open(home).ok())
            .and_then(|store| store.get_title(&identity.session_id).ok().flatten())
            .filter(|value| !value.trim().is_empty() && !looks_like_generated_fallback_title(value))
            .unwrap_or_else(|| short_session_id(&identity.session_id));
        session.title = title;
    }
}

pub(crate) fn overlay_claude_code_runtime_managed_identity(
    session: &mut ManagedSessionView,
    identity: &ClaudeCodeRuntimeProcessIdentity,
) {
    if session.kind != SessionKind::ClaudeCode {
        return;
    }
    let runtime_key = session.session_path.clone();
    let title_was_generated = session.title.trim().is_empty()
        || looks_like_generated_fallback_title(&session.title);
    repoint_stored_launch_command_session_id(session, &identity.session_id);
    session.id = identity.session_id.clone();
    upsert_session_metadata(
        &mut session.metadata,
        "Storage",
        identity.storage_path.display().to_string(),
    );
    upsert_session_metadata(
        &mut session.metadata,
        "Claude Code Session",
        identity.session_id.clone(),
    );
    upsert_session_metadata(&mut session.metadata, "Runtime Session", runtime_key);
    if !identity.cwd.trim().is_empty() {
        upsert_session_metadata(&mut session.metadata, "Cwd", identity.cwd.clone());
    }
    if title_was_generated {
        session.title = short_session_id(&identity.session_id);
    }
}

pub(crate) fn overlay_codex_runtime_managed_identity(
    session: &mut ManagedSessionView,
    identity: &CodexRuntimeProcessIdentity,
    yggterm_home: Option<&Path>,
) {
    if session.kind != SessionKind::Codex {
        return;
    }
    let runtime_key = session.session_path.clone();
    let title_was_generated = session.title.trim().is_empty()
        || looks_like_generated_fallback_title(&session.title)
        || parse_remote_runtime_codex_session_key(&runtime_key)
            .is_some_and(|runtime_id| session.title.contains(runtime_id));
    repoint_stored_launch_command_session_id(session, &identity.session_id);
    session.id = identity.session_id.clone();
    upsert_session_metadata(
        &mut session.metadata,
        "Storage",
        identity.storage_path.display().to_string(),
    );
    upsert_session_metadata(
        &mut session.metadata,
        "Codex Session",
        identity.session_id.clone(),
    );
    upsert_session_metadata(&mut session.metadata, "Runtime Session", runtime_key);
    session
        .metadata
        .retain(|entry| entry.label != REMOTE_LAUNCH_ACTION_METADATA_LABEL);
    if !identity.cwd.trim().is_empty() {
        upsert_session_metadata(&mut session.metadata, "Cwd", identity.cwd.clone());
    }
    if title_was_generated {
        let title = yggterm_home
            .and_then(|home| SessionTitleStore::open(home).ok())
            .and_then(|store| store.get_title(&identity.session_id).ok().flatten())
            .filter(|value| !value.trim().is_empty() && !looks_like_generated_fallback_title(value))
            .unwrap_or_else(|| short_session_id(&identity.session_id));
        session.title = title;
    }
}

fn push_unique_session_alias(candidates: &mut Vec<String>, value: impl AsRef<str>) {
    let value = value.as_ref().trim();
    if value.is_empty() || candidates.iter().any(|candidate| candidate == value) {
        return;
    }
    candidates.push(value.to_string());
}

fn codex_runtime_title_alias_candidates(
    storage_key: &str,
    session: &ManagedSessionView,
) -> Vec<String> {
    let mut candidates = Vec::new();
    push_unique_session_alias(&mut candidates, &session.id);
    if let Some((_, session_id)) = parse_remote_scanned_session_path(storage_key) {
        push_unique_session_alias(&mut candidates, session_id);
    }
    if let Some(session_id) = parse_remote_runtime_codex_session_key(storage_key) {
        push_unique_session_alias(&mut candidates, session_id);
    }
    if let Some(session_id) = local_runtime_id_from_key(storage_key) {
        push_unique_session_alias(&mut candidates, session_id);
    }
    for label in ["Codex Session", "Runtime Session"] {
        if let Some(value) = session_metadata_value(session, label) {
            push_unique_session_alias(&mut candidates, &value);
            if let Some((_, session_id)) = parse_remote_scanned_session_path(&value) {
                push_unique_session_alias(&mut candidates, session_id);
            }
            if let Some(session_id) = parse_remote_runtime_codex_session_key(&value) {
                push_unique_session_alias(&mut candidates, session_id);
            }
            if let Some(session_id) = local_runtime_id_from_key(&value) {
                push_unique_session_alias(&mut candidates, session_id);
            }
        }
    }
    candidates
}

fn migrate_codex_runtime_title_aliases(
    yggterm_home: Option<&Path>,
    canonical_session_id: &str,
    cwd: &str,
    candidates: Vec<String>,
) -> bool {
    let Some(yggterm_home) = yggterm_home else {
        return false;
    };
    let Ok(store) = SessionTitleStore::open(yggterm_home) else {
        return false;
    };
    let mut migrated = false;
    for candidate in candidates {
        if candidate == canonical_session_id {
            continue;
        }
        match store.copy_meaningful_title_alias(&candidate, canonical_session_id, cwd) {
            Ok(true) => {
                migrated = true;
            }
            Ok(false) => {}
            Err(error) => {
                warn!(
                    from_session_id = %candidate,
                    to_session_id = %canonical_session_id,
                    error = %error,
                    "failed to migrate Codex runtime title alias"
                );
            }
        }
        match store.copy_meaningful_summary_alias(&candidate, canonical_session_id, cwd) {
            Ok(true) => {
                migrated = true;
            }
            Ok(false) => {}
            Err(error) => {
                warn!(
                    from_session_id = %candidate,
                    to_session_id = %canonical_session_id,
                    error = %error,
                    "failed to migrate Codex runtime summary alias"
                );
            }
        }
    }
    migrated
}

fn summary_metadata_value(entries: &[SessionMetadataEntry], label: &str) -> Option<String> {
    entries
        .iter()
        .find(|entry| entry.label == label)
        .map(|entry| entry.value.trim().to_string())
        .filter(|value| !value.is_empty())
}

fn remote_scanned_session_from_live_codex(
    machine_key: &str,
    session: &ManagedSessionView,
    path_session_id: &str,
    live_runtime: bool,
) -> Option<RemoteScannedSession> {
    if session.kind != SessionKind::Codex {
        return None;
    }
    let storage_path = session_metadata_value(session, "Storage").unwrap_or_default();
    if storage_path.trim().is_empty() {
        return None;
    }
    let session_id = session_metadata_value(session, "Codex Session")
        .map(|value| value.trim().to_string())
        .filter(|value| !value.is_empty())
        .unwrap_or_else(|| path_session_id.to_string());
    let cwd = session_metadata_value(session, "Cwd")
        .map(|value| value.trim().to_string())
        .filter(|value| !value.is_empty())?;
    let title_hint =
        if session.title.trim().is_empty() || looks_like_generated_fallback_title(&session.title) {
            short_session_id(&session_id)
        } else {
            session.title.clone()
        };
    Some(RemoteScannedSession {
        session_path: remote_scanned_session_path(machine_key, &session_id),
        session_id,
        cwd,
        started_at: metadata_value(session, "Started"),
        modified_epoch: 0,
        event_count: 0,
        user_message_count: 0,
        assistant_message_count: 0,
        title_hint,
        recent_context: String::new(),
        cached_precis: summary_metadata_value(&session.preview.summary, "Precis")
            .or_else(|| session_metadata_value(session, "Precis")),
        cached_summary: summary_metadata_value(&session.preview.summary, "Summary")
            .or_else(|| session_metadata_value(session, "Summary")),
        live_runtime,
        storage_path,
    })
}

fn local_runtime_id_from_key(key: &str) -> Option<&str> {
    key.strip_prefix("local://")
        .or_else(|| key.strip_prefix("local::"))
        .or_else(|| key.strip_prefix("codex://"))
        .or_else(|| key.strip_prefix("codex::"))
        .or_else(|| key.strip_prefix("codex-runtime://"))
        .or_else(|| key.strip_prefix("codex-litellm://"))
        .or_else(|| key.strip_prefix("codex-litellm::"))
        .filter(|id| !id.trim().is_empty())
}

pub(crate) fn local_live_runtime_key(session_id: &str) -> String {
    format!("local://{session_id}")
}

/// A stored DOCUMENT must never own a terminal-runtime URI as its path. Such an
/// entry is a bogus dual-store twin (Bug 9 / [[finding-dual-store-codex-mount-
/// failure-on-restart]]): the same UUID then exists as BOTH a kind=document
/// "web view only" stored row AND a live codex runtime, so the GUI oscillates
/// between Rendered (document identity) and Terminal (codex identity) — the ~3s
/// blink with intermittent broken bottom paint. Real documents use virtual paths
/// (e.g. `/documents/...`), never `local://` / `codex-runtime://` / `codex://`.
/// Filtering these at persist + restore keeps the collision from surviving.
fn stored_document_owns_runtime_uri(kind: SessionKind, path: &str) -> bool {
    kind == SessionKind::Document && local_runtime_id_from_key(path).is_some()
}

fn canonical_local_live_runtime_key(key: &str, session_id: &str) -> String {
    if key.starts_with("codex-runtime://") {
        return key.to_string();
    }
    local_runtime_id_from_key(key)
        .map(local_live_runtime_key)
        .unwrap_or_else(|| local_live_runtime_key(session_id))
}

fn managed_session_is_promoted_live_session(key: &str, session: &ManagedSessionView) -> bool {
    if !matches!(
        session.source,
        SessionSource::LiveLocal | SessionSource::LiveSsh
    ) || session.kind == SessionKind::Document
    {
        return false;
    }
    if is_local_codex_storage_session_path(key)
        || is_local_codex_storage_session_path(&session.session_path)
    {
        return false;
    }
    true
}

fn managed_session_is_live_runtime_session(key: &str, session: &ManagedSessionView) -> bool {
    managed_session_is_promoted_live_session(key, session)
        || (matches!(
            session.source,
            SessionSource::LiveLocal | SessionSource::LiveSsh
        ) && matches!(session.kind, SessionKind::Codex | SessionKind::CodexLiteLlm)
            && (is_local_codex_storage_session_path(key)
                || is_local_codex_storage_session_path(&session.session_path)))
}

fn live_session_uses_remote_runtime(session: &ManagedSessionView) -> bool {
    session.source == SessionSource::LiveSsh
        && (is_remote_scanned_live_session_path(&session.session_path)
            || session.session_path.starts_with("ssh://"))
}

fn remote_live_session_starts_new_codex(session: &ManagedSessionView) -> bool {
    session_metadata_value(session, REMOTE_LAUNCH_ACTION_METADATA_LABEL).as_deref()
        == Some("start-codex")
}

fn session_is_temporary_update_restore(session: &ManagedSessionView) -> bool {
    session_metadata_value(session, RUNTIME_RESTORE_REASON_METADATA_LABEL).as_deref()
        == Some(UPDATE_RESTART_RESTORE_REASON)
}

fn remote_scanned_session_path_is_live(
    remote_machines: &[RemoteMachineSnapshot],
    session_path: &str,
) -> bool {
    let Some((raw_machine_key, session_id)) = parse_remote_scanned_session_path(session_path)
    else {
        return false;
    };
    let machine_key = normalize_machine_key(raw_machine_key);
    remote_machines
        .iter()
        .find(|machine| machine.machine_key == machine_key)
        .and_then(|machine| {
            machine.sessions.iter().find(|session| {
                session.session_path == session_path || session.session_id == session_id
            })
        })
        .is_some_and(|session| session.live_runtime)
}

fn clear_remote_machine_live_runtime_flags(
    remote_machines: &[RemoteMachineSnapshot],
) -> Vec<RemoteMachineSnapshot> {
    remote_machines
        .iter()
        .cloned()
        .map(|mut machine| {
            machine.sessions.retain(remote_scanned_session_is_durable);
            for session in &mut machine.sessions {
                session.live_runtime = false;
            }
            machine
        })
        .collect()
}

fn remote_scanned_session_is_durable(session: &RemoteScannedSession) -> bool {
    !session.storage_path.trim().is_empty()
}

