    /// Live remote-Codex sessions that still carry a synthesized UUIDv4 id and
    /// therefore need a real CLI session id discovered over SSH
    /// (`[[finding-uuidv4-codex-session-drift]]` Stage 2). The local PTY-tree
    /// walk used for local Codex/CC sessions cannot reach a remote machine, so
    /// these are the rows the remote identity poll targets. A session drops out
    /// of this list as soon as its id has been rebound to a real id, which makes
    /// the poll self-limiting.
    pub(crate) fn live_remote_codex_sessions_needing_identity_poll(
        &self,
    ) -> Vec<RemoteCodexIdentityPollTarget> {
        self.live_session_order
            .iter()
            .filter_map(|key| {
                let session = self.sessions.get(key)?;
                if session.kind != SessionKind::Codex
                    || !managed_session_is_live_runtime_session(key, session)
                {
                    return None;
                }
                let ssh_target = session
                    .ssh_target
                    .as_deref()
                    .filter(|target| !is_loopback_ssh_target(target))?;
                if !looks_like_synthesized_uuidv4_session_id(&session.id) {
                    return None;
                }
                let cwd = session_metadata_value(session, "Cwd")
                    .filter(|value| !value.trim().is_empty())?;
                Some(RemoteCodexIdentityPollTarget {
                    key: key.clone(),
                    ssh_target: ssh_target.to_string(),
                    ssh_prefix: session.ssh_prefix.clone(),
                    cwd,
                    current_id: session.id.clone(),
                })
            })
            .collect()
    }

    /// Mirrors `apply_codex_runtime_identity_to_live_session` for Claude Code.
    /// Closes the same UUIDv4-vs-real-session-id drift the codex rebind
    /// addresses, applied to local CC sessions whose `~/.claude/projects/...`
    /// JSONL was discovered by walking the live PTY's process tree.
    pub(crate) fn apply_claude_code_runtime_identity_to_live_session(
        &mut self,
        key_or_path: &str,
        identity: &ClaudeCodeRuntimeProcessIdentity,
    ) -> bool {
        let Some(key) = self
            .resolve_session_storage_key(key_or_path)
            .map(str::to_string)
        else {
            return false;
        };
        let Some(session) = self.sessions.get_mut(&key) else {
            return false;
        };
        if session.kind != SessionKind::ClaudeCode
            || !matches!(
                session.source,
                SessionSource::LiveLocal | SessionSource::LiveSsh
            )
        {
            return false;
        }
        overlay_claude_code_runtime_managed_identity(session, identity);
        true
    }

    pub(crate) fn apply_codex_runtime_identity_to_live_session(
        &mut self,
        key_or_path: &str,
        identity: &CodexRuntimeProcessIdentity,
        yggterm_home: Option<&Path>,
    ) -> bool {
        let Some(key) = self
            .resolve_session_storage_key(key_or_path)
            .map(str::to_string)
        else {
            return false;
        };
        let Some(session) = self.sessions.get_mut(&key) else {
            return false;
        };
        if session.kind != SessionKind::Codex
            || !matches!(
                session.source,
                SessionSource::LiveLocal | SessionSource::LiveSsh
            )
        {
            return false;
        }
        let title_alias_candidates = codex_runtime_title_alias_candidates(&key, session);
        let title_alias_cwd = if identity.cwd.trim().is_empty() {
            session_metadata_value(session, "Cwd").unwrap_or_default()
        } else {
            identity.cwd.clone()
        };
        migrate_codex_runtime_title_aliases(
            yggterm_home,
            &identity.session_id,
            &title_alias_cwd,
            title_alias_candidates,
        );
        overlay_codex_runtime_managed_identity(session, identity, yggterm_home);
        let session = session.clone();
        self.promote_remote_codex_live_session_to_scanned(&key, &session, true);
        true
    }

    pub fn snapshot(&self) -> ServerUiSnapshot {
        let live_sessions = self
            .live_session_order
            .iter()
            .filter_map(|key| {
                self.sessions
                    .get(key)
                    .filter(|session| managed_session_is_live_runtime_session(key, session))
            })
            .map(snapshot_live_session_view)
            .collect::<Vec<_>>();
        let active_session = self.active_session().cloned().or_else(|| {
            self.active_session_path.as_deref().and_then(|path| {
                synthesize_remote_active_preview_session(
                    path,
                    &self.remote_machines,
                    self.backend,
                    self.theme,
                    self.ghostty_host.bridge_enabled,
                )
            })
        });
        let active_session_path = active_session
            .as_ref()
            .map(|session| session.session_path.clone());
        let active_view_mode =
            snapshot_active_view_mode_for_session(self.active_view_mode, active_session.as_ref());
        let snapshot = ServerUiSnapshot {
            active_session_path,
            active_session: active_session.map(snapshot_session_view),
            active_view_mode,
            remote_machines: self.remote_machines.clone(),
            ssh_targets: self.ssh_targets.clone(),
            live_sessions,
        };
        let invariant_violations = validate_server_ui_snapshot(&snapshot);
        if !invariant_violations.is_empty() {
            warn!(
                violations = ?invariant_violations,
                "server UI snapshot violates the session/view contract"
            );
        }
        snapshot
    }

    pub fn payload_stats(&self) -> SessionPayloadStats {
        self.sessions.values().fold(
            SessionPayloadStats {
                session_count: self.sessions.len(),
                ..SessionPayloadStats::default()
            },
            |mut stats, session| {
                stats.metadata_entries += session.metadata.len() + session.preview.summary.len();
                stats.metadata_bytes += session
                    .metadata
                    .iter()
                    .map(|entry| entry.label.len() + entry.value.len())
                    .sum::<usize>();
                stats.metadata_bytes += session
                    .preview
                    .summary
                    .iter()
                    .map(|entry| entry.label.len() + entry.value.len())
                    .sum::<usize>();
                stats.preview_blocks += session.preview.blocks.len();
                for block in &session.preview.blocks {
                    stats.preview_lines += block.lines.len();
                    stats.preview_bytes += block.role.len() + block.timestamp.len();
                    stats.preview_bytes += block.lines.iter().map(|line| line.len()).sum::<usize>();
                }
                stats.rendered_sections += session.rendered_sections.len();
                for section in &session.rendered_sections {
                    stats.rendered_lines += section.lines.len();
                    stats.rendered_bytes += section.title.len();
                    stats.rendered_bytes +=
                        section.lines.iter().map(|line| line.len()).sum::<usize>();
                }
                stats.terminal_lines += session.terminal_lines.len();
                stats.terminal_bytes += session
                    .terminal_lines
                    .iter()
                    .map(|line| line.len())
                    .sum::<usize>();
                stats.total_bytes = stats.metadata_bytes
                    + stats.preview_bytes
                    + stats.rendered_bytes
                    + stats.terminal_bytes;
                stats
            },
        )
    }

    pub fn apply_snapshot(&mut self, mut snapshot: ServerUiSnapshot) {
        for target in &self.ssh_targets {
            let target_key = (
                target.kind,
                canonicalize_ssh_target_alias(&target.ssh_target),
                target.prefix.clone(),
            );
            if !snapshot.ssh_targets.iter().any(|candidate| {
                (
                    candidate.kind,
                    canonicalize_ssh_target_alias(&candidate.ssh_target),
                    candidate.prefix.clone(),
                ) == target_key
            }) {
                snapshot.ssh_targets.push(target.clone());
            }
        }
        for machine in &self.remote_machines {
            let machine_key = normalize_machine_key(&machine.machine_key);
            if !snapshot
                .remote_machines
                .iter()
                .any(|candidate| normalize_machine_key(&candidate.machine_key) == machine_key)
            {
                snapshot.remote_machines.push(machine.clone());
            }
        }
        self.active_view_mode = snapshot.active_view_mode;
        self.active_session_path = snapshot.active_session_path.clone();
        self.remote_machines = snapshot.remote_machines;
        self.ssh_targets = snapshot.ssh_targets;
        for target in self.ssh_targets.clone() {
            self.ensure_remote_machine_stub(&target);
        }
        self.live_session_order = snapshot
            .live_sessions
            .iter()
            .map(|session| session.session_path.clone())
            .collect();
        self.sessions.clear();
        if let Some(active) = snapshot.active_session {
            let key = active.session_path.clone();
            self.sessions
                .insert(key, managed_session_from_snapshot(active));
        }
        for live in snapshot.live_sessions {
            let key = live.session_path.clone();
            self.sessions
                .insert(key, managed_session_from_snapshot(live));
        }
        if let Some(active_path) = self.active_session_path.clone()
            && !self.sessions.contains_key(&active_path)
            && let Some(session) = synthesize_remote_active_preview_session(
                &active_path,
                &self.remote_machines,
                self.backend,
                self.theme,
                self.ghostty_host.bridge_enabled,
            )
        {
            if self.active_view_mode == WorkspaceViewMode::Terminal {
                self.active_view_mode = WorkspaceViewMode::Rendered;
            }
            self.sessions.insert(active_path, session);
        }
        if self
            .active_session_path
            .as_ref()
            .is_some_and(|path| !self.sessions.contains_key(path))
        {
            self.active_session_path = self.live_session_order.first().cloned();
        }
        self.normalize_active_view_mode();
    }

    pub fn remote_preview_snapshot_session_for_path(
        &self,
        path: &str,
    ) -> Option<SnapshotSessionView> {
        synthesize_remote_active_preview_session(
            path,
            &self.remote_machines,
            self.backend,
            self.theme,
            self.ghostty_host.bridge_enabled,
        )
        .map(snapshot_session_view)
    }

    pub fn persisted_state(&self) -> PersistedDaemonState {
        self.persisted_state_with_update_protection(false, None)
    }

    pub fn persisted_state_for_update_restart(&self) -> PersistedDaemonState {
        self.persisted_state_with_update_protection(true, None)
    }

    pub fn persisted_state_for_update_restart_with_runtime_keys(
        &self,
        runtime_keys: &HashSet<String>,
    ) -> PersistedDaemonState {
        self.persisted_state_with_update_protection(true, Some(runtime_keys))
    }

    fn persisted_state_with_update_protection(
        &self,
        protect_all_live: bool,
        protected_runtime_keys: Option<&HashSet<String>>,
    ) -> PersistedDaemonState {
        let stored_sessions = self
            .sessions
            .iter()
            .filter(|(path, session)| {
                // Bug 9: never persist a kind=document stored twin that owns a runtime
                // URI — it collides with the live codex of the same UUID (the blink).
                !stored_document_owns_runtime_uri(session.kind, path)
            })
            .filter_map(|(path, session)| {
                (session.source == SessionSource::Stored).then(|| PersistedStoredSession {
                    path: path.clone(),
                    kind: session.kind,
                    session_id: Some(session.id.clone()),
                    cwd: session
                        .metadata
                        .iter()
                        .find(|entry| entry.label == "Cwd")
                        .map(|entry| entry.value.clone()),
                    title_hint: Some(session.title.clone()),
                })
            })
            .collect();
        // Persistence-drop telemetry (live incident 2026-06-11: local rows
        // kept vanishing at swaps even after the mapper fix; the unit test
        // passed while the live path failed). Every live key that does NOT
        // make it into the persisted state traces WHICH gate dropped it.
        let trace_drop = |key: &str, reason: &str, detail: serde_json::Value| {
            if let Ok(home) = resolve_yggterm_home() {
                append_trace_event(
                    &home,
                    "server",
                    "persist",
                    "live_session_persist_dropped",
                    serde_json::json!({
                        "key": key,
                        "reason": reason,
                        "detail": detail,
                        "protect_all_live": protect_all_live,
                    }),
                );
            }
        };
        let live_sessions: Vec<_> = self
            .live_session_order
            .iter()
            .filter_map(|key| self.sessions.get(key).map(|session| (key, session)))
            .filter(|(key, session)| {
                let recoverable = managed_live_session_is_recoverable(key, session);
                if !recoverable {
                    trace_drop(
                        key,
                        "not_recoverable",
                        serde_json::json!({
                            "kind": format!("{:?}", session.kind),
                            "source": format!("{:?}", session.source),
                            "ssh_target": session.ssh_target,
                        }),
                    );
                }
                recoverable
            })
            .filter_map(|(key, session)| {
                let keep_alive = session_keep_alive(session);
                if !keep_alive && !protect_all_live {
                    return None;
                }
                if !keep_alive && let Some(protected_runtime_keys) = protected_runtime_keys {
                    let runtime_key = self.terminal_runtime_key_for_path(key);
                    // Bug-9 key duality (drop-telemetry catch, 2026-06-11): a
                    // local row keyed local://<uuid> can own its PTY under
                    // codex-runtime://<uuid> in the terminals manager — the
                    // protected set holds THAT form, so matching only the row
                    // key + resolved runtime key silently dropped working
                    // local sessions at every update persist.
                    let codex_runtime_alias =
                        local_runtime_id_from_key(key).map(remote_runtime_codex_session_key);
                    let protected = protected_runtime_keys.contains(key)
                        || protected_runtime_keys.contains(&runtime_key)
                        || codex_runtime_alias
                            .as_ref()
                            .is_some_and(|alias| protected_runtime_keys.contains(alias));
                    if !protected {
                        trace_drop(
                            key,
                            "not_in_protected_runtime_keys",
                            serde_json::json!({
                                "resolved_runtime_key": runtime_key,
                                "protected_count": protected_runtime_keys.len(),
                            }),
                        );
                        return None;
                    }
                }
                let restore_reason = (!keep_alive && protect_all_live)
                    .then(|| UPDATE_RESTART_RESTORE_REASON.to_string());
                let persisted = persisted_live_session_from_managed(
                    key,
                    session,
                    keep_alive,
                    restore_reason,
                    protect_all_live,
                );
                if persisted.is_none() {
                    trace_drop(
                        key,
                        "mapper_returned_none",
                        serde_json::json!({
                            "kind": format!("{:?}", session.kind),
                            "source": format!("{:?}", session.source),
                        }),
                    );
                }
                persisted
            })
            .collect();
        let persisted_live_keys: HashSet<_> =
            live_sessions.iter().map(|live| live.key.as_str()).collect();
        let active_points_at_excluded_live = self
            .active_session_path
            .as_deref()
            .and_then(|active_path| {
                self.sessions
                    .get(active_path)
                    .map(|session| (active_path, session))
            })
            .is_some_and(|(active_path, session)| {
                managed_session_is_promoted_live_session(active_path, session)
                    && !persisted_live_keys.contains(active_path)
            });
        let active_session_path = if active_points_at_excluded_live {
            live_sessions.first().map(|live| live.key.clone())
        } else {
            self.active_session_path.clone()
        };
        let active_view_mode = if active_session_path.is_none()
            && self.active_view_mode == WorkspaceViewMode::Terminal
        {
            WorkspaceViewMode::Rendered
        } else {
            self.active_view_mode
        };

        // Persist the last-known PTY grid for every session we still know about, so a
        // daemon-PROCESS restart re-resumes each at its real grid (squish fix, Bug 10).
        // Keyed by session key, this covers BOTH local-live (no ssh_target, so absent
        // from live_sessions) AND remote/stored — the squish hits both. Filtering to
        // keys still present in `self.sessions` prunes deleted sessions so the map
        // can't grow unbounded.
        let mut session_pty_grids: Vec<PersistedSessionGrid> = self
            .session_pty_grids
            .iter()
            .filter(|(key, _)| self.sessions.contains_key(key.as_str()))
            .map(|(key, (cols, rows))| PersistedSessionGrid {
                key: key.clone(),
                cols: *cols,
                rows: *rows,
            })
            .collect();
        session_pty_grids.sort_by(|a, b| a.key.cmp(&b.key));

        PersistedDaemonState {
            active_session_path,
            active_view_mode,
            ssh_targets: self.ssh_targets.clone(),
            remote_machines: clear_remote_machine_live_runtime_flags(&self.remote_machines),
            stored_sessions,
            live_sessions,
            session_pty_grids,
        }
    }

    pub fn restore_persisted_state(
        &mut self,
        state: PersistedDaemonState,
        store: Option<&SessionStore>,
    ) {
        self.restore_persisted_state_with_launch_policy(state, store, true);
    }

    pub fn restore_persisted_state_with_launch_policy(
        &mut self,
        state: PersistedDaemonState,
        store: Option<&SessionStore>,
        launch_active_terminal: bool,
    ) {
        let perf_home = resolve_yggterm_home().ok();
        let total_restore_perf = perf_home
            .clone()
            .map(|home| PerfSpan::start(home, "server", "restore_persisted_state"));
        // Restore last-known PTY grids first so a re-resumed session (squish fix,
        // Bug 10) comes back at its real grid instead of DEFAULT 120×36.
        self.session_pty_grids = state
            .session_pty_grids
            .iter()
            .filter(|grid| grid.cols != 0 && grid.rows != 0)
            .map(|grid| (grid.key.clone(), (grid.cols, grid.rows)))
            .collect();
        self.ssh_targets = state
            .ssh_targets
            .into_iter()
            .filter_map(|mut target| {
                target.ssh_target = canonicalize_ssh_target_alias(&target.ssh_target);
                if is_loopback_ssh_target(&target.ssh_target) {
                    return None;
                }
                target.label = ssh_machine_label(&target);
                Some(target)
            })
            .collect();
        for target in &mut self.ssh_targets {
            target.label = ssh_machine_label(target);
        }
        self.remote_machines = state
            .remote_machines
            .into_iter()
            .filter_map(|mut machine| {
                let legacy_machine_key = machine.machine_key.clone();
                machine.machine_key = normalize_machine_key(&machine.machine_key);
                machine.ssh_target = canonicalize_ssh_target_alias(&machine.ssh_target);
                if is_loopback_ssh_target(&machine.ssh_target) {
                    return None;
                }
                let mirrored_sessions =
                    load_remote_machine_sessions_from_mirror(&machine.machine_key)
                        .or_else(|_| load_remote_machine_sessions_from_mirror(&legacy_machine_key))
                        .unwrap_or_default();
                machine.sessions = if machine.sessions.is_empty() {
                    mirrored_sessions
                        .into_iter()
                        .filter(remote_scanned_session_is_durable)
                        .collect()
                } else {
                    if !mirrored_sessions.is_empty() {
                        machine.sessions = overlay_mirrored_remote_sessions(
                            &machine.machine_key,
                            &machine.sessions,
                        );
                    }
                    machine.sessions = machine
                        .sessions
                        .into_iter()
                        .map(|mut session| {
                            if let Some((session_machine_key, session_id)) =
                                parse_remote_scanned_session_path(&session.session_path)
                            {
                                let canonical_session_machine_key =
                                    normalize_machine_key(session_machine_key);
                                if canonical_session_machine_key != machine.machine_key {
                                    session.session_path = remote_scanned_session_path(
                                        &machine.machine_key,
                                        session_id,
                                    );
                                }
                            }
                            session
                        })
                        .filter(remote_scanned_session_is_durable)
                        .collect::<Vec<_>>();
                    if !machine.sessions.is_empty() {
                        overlay_mirrored_remote_sessions(&machine.machine_key, &machine.sessions)
                            .into_iter()
                            .filter(remote_scanned_session_is_durable)
                            .collect()
                    } else {
                        machine.sessions.clone()
                    }
                };
                if !machine.sessions.is_empty() {
                    machine.health = RemoteMachineHealth::Cached;
                }
                for session in &mut machine.sessions {
                    session.live_runtime = false;
                }
                Some(machine)
            })
            .map(|mut machine| {
                if machine.health == RemoteMachineHealth::Healthy {
                    machine.health = RemoteMachineHealth::Cached;
                }
                machine
            })
            .collect();
        for target in self.ssh_targets.clone() {
            self.ensure_remote_machine_stub(&target);
        }
        for machine in &mut self.remote_machines {
            if machine.sessions.is_empty()
                && let Ok(mirrored) = load_remote_machine_sessions_from_mirror(&machine.machine_key)
                && !mirrored.is_empty()
            {
                machine.sessions = mirrored
                    .into_iter()
                    .filter(remote_scanned_session_is_durable)
                    .collect();
                machine.health = RemoteMachineHealth::Cached;
            }
        }
        let desired_active_path = state.active_session_path.clone();
        let normalized_desired_active_path = desired_active_path.as_deref().map(|path| {
            if let Some((machine_key, session_id)) = parse_remote_scanned_session_path(path) {
                remote_scanned_session_path(&normalize_machine_key(machine_key), session_id)
            } else if path.starts_with("codex-runtime://") {
                path.to_string()
            } else if let Some(session_id) = local_runtime_id_from_key(path) {
                local_live_runtime_key(session_id)
            } else {
                path.to_string()
            }
        });
        let stored_restore_perf = perf_home
            .clone()
            .map(|home| PerfSpan::start(home, "server", "restore_stored_sessions"));
        for session in state.stored_sessions {
            // Bug 9 defense-in-depth: drop a stale kind=document stored twin that owns
            // a runtime URI so it can't be restored alongside (and collide with) the
            // live codex of the same UUID. This cleans up twins already on disk.
            if stored_document_owns_runtime_uri(session.kind, &session.path) {
                continue;
            }
            let path = if let Some((machine_key, session_id)) =
                parse_remote_scanned_session_path(&session.path)
            {
                remote_scanned_session_path(&normalize_machine_key(machine_key), session_id)
            } else {
                session.path.clone()
            };
            let was_missing = !self.sessions.contains_key(&path);
            let hydration_mode = if session.kind == SessionKind::Document
                || normalized_desired_active_path
                    .as_deref()
                    .is_some_and(|active_path| active_path == path)
            {
                StoredPreviewHydrationMode::Eager
            } else {
                StoredPreviewHydrationMode::Deferred
            };
            let document = if session.kind == SessionKind::Document {
                store.and_then(|store| store.load_document(&path).ok().flatten())
            } else {
                None
            };
            let entry = self.sessions.entry(path.clone()).or_insert_with(|| {
                build_session(
                    session.kind,
                    &path,
                    session.session_id.as_deref(),
                    session.cwd.as_deref(),
                    session.title_hint.as_deref(),
                    document.as_ref(),
                    self.backend,
                    self.theme,
                    self.ghostty_host.bridge_enabled,
                    hydration_mode,
                )
            });
            entry.kind = session.kind;
            entry.backend = self.backend;
            if let Some(session_id) = session.session_id.as_deref() {
                entry.id = session_id.to_string();
            }
            if let Some(cwd) = session.cwd.as_deref() {
                entry.metadata.retain(|entry| entry.label != "Cwd");
                entry.metadata.push(SessionMetadataEntry {
                    label: "Cwd",
                    value: cwd.to_string(),
                });
            }
            if let Some(title_hint) = session.title_hint.as_deref() {
                if passive_title_hint_can_update(&entry.title, title_hint, was_missing) {
                    entry.title = title_hint.to_string();
                }
            }
            if let Some(document) = document.as_ref() {
                hydrate_document_session(entry, document);
            }
            entry.stored_preview_hydrated = session.kind == SessionKind::Document
                || matches!(hydration_mode, StoredPreviewHydrationMode::Eager);
        }
        if let Some(span) = stored_restore_perf {
            span.finish(serde_json::json!({
                "stored_sessions": self
                    .sessions
                    .values()
                    .filter(|session| session.source == SessionSource::Stored)
                    .count(),
            }));
        }
        let mut restored_live_keys = HashSet::<String>::new();
        for live in state.live_sessions {
            if !persisted_live_session_is_recoverable(&live) || is_legacy_demo_live_session(&live) {
                continue;
            }
            let dedupe_key = if let Some((machine_key, session_id)) =
                parse_remote_scanned_session_path(&live.key)
            {
                remote_scanned_session_path(&normalize_machine_key(machine_key), session_id)
            } else if live.key.starts_with("codex-runtime://") {
                live.key.clone()
            } else if let Some(session_id) = local_runtime_id_from_key(&live.key) {
                local_live_runtime_key(session_id)
            } else {
                live.key.clone()
            };
            if !restored_live_keys.insert(dedupe_key) {
                continue;
            }
            self.restore_live_session(live);
        }
        self.active_view_mode = state.active_view_mode;
        if let Some(path) = desired_active_path {
            let active_path =
                if let Some((machine_key, session_id)) = parse_remote_scanned_session_path(&path) {
                    remote_scanned_session_path(&normalize_machine_key(machine_key), session_id)
                } else if path.starts_with("codex-runtime://") {
                    path
                } else if let Some(session_id) = local_runtime_id_from_key(&path) {
                    local_live_runtime_key(session_id)
                } else {
                    path
                };
            if !self.sessions.contains_key(&active_path)
                && let Some(session) = synthesize_remote_active_preview_session(
                    &active_path,
                    &self.remote_machines,
                    self.backend,
                    self.theme,
                    self.ghostty_host.bridge_enabled,
                )
            {
                if self.active_view_mode == WorkspaceViewMode::Terminal {
                    self.active_view_mode = WorkspaceViewMode::Rendered;
                }
                self.sessions.insert(active_path.clone(), session);
            }
            if self.sessions.contains_key(&active_path) {
                self.active_session_path = Some(active_path.clone());
                if let Some(existing) = self.sessions.get(&active_path).cloned()
                    && existing.source == SessionSource::Stored
                    && !existing.stored_preview_hydrated
                {
                    let _ = self.refresh_stored_session_preview(&active_path, &existing);
                }
                if launch_active_terminal
                    && self.active_view_mode == WorkspaceViewMode::Terminal
                    && (parse_remote_scanned_session_path(&active_path).is_none()
                        || remote_scanned_session_path_is_live(&self.remote_machines, &active_path))
                {
                    self.request_terminal_launch_for_path(&active_path);
                }
            }
        }
        self.normalize_active_view_mode();
        if let Some(span) = total_restore_perf {
            span.finish(serde_json::json!({
                "sessions": self.sessions.len(),
                "remote_machines": self.remote_machines.len(),
                "live_sessions": self.live_session_order.len(),
            }));
        }
    }

    pub fn focus_live_session(&mut self, key: &str) {
        let resolved_key = self.resolve_live_session_key(key);
        if let Some(resolved_key) = resolved_key {
            self.active_session_path = Some(resolved_key);
            self.active_view_mode = WorkspaceViewMode::Terminal;
            self.request_terminal_launch_for_active();
        }
    }

    pub fn connect_ssh_target(
        &mut self,
        target_ix: usize,
    ) -> anyhow::Result<(Option<String>, bool)> {
        let Some(target) = self.ssh_targets.get(target_ix).cloned() else {
            return Ok((None, false));
        };
        self.connect_ssh_like_target(&target)
    }

    pub fn connect_ssh_custom(
        &mut self,
        target: &str,
        prefix: Option<&str>,
    ) -> anyhow::Result<(String, bool)> {
        let ssh_target = canonicalize_ssh_target_alias(target);
        if ssh_target.is_empty() {
            anyhow::bail!("enter an SSH target such as dev, pi@raspberry, or user@ip");
        }
        let prefix = prefix
            .map(str::trim)
            .filter(|value| !value.is_empty())
            .map(ToOwned::to_owned);
        let label = ssh_target
            .rsplit('@')
            .next()
            .unwrap_or(ssh_target.as_str())
            .to_string();
        let target = SshConnectTarget {
            label,
            kind: SessionKind::SshShell,
            ssh_target,
            prefix,
            cwd: None,
        };
        let (key, reused) = self.connect_ssh_like_target(&target)?;
        key.map(|key| (key, reused))
            .ok_or_else(|| anyhow::anyhow!("failed to create ssh session"))
    }

    pub fn start_ssh_session(
        &mut self,
        target: &str,
        prefix: Option<&str>,
        cwd: Option<&str>,
        title_hint: Option<&str>,
    ) -> anyhow::Result<String> {
        let ssh_target = canonicalize_ssh_target_alias(target);
        if ssh_target.is_empty() {
            anyhow::bail!("enter an SSH target such as dev, pi@raspberry, or user@ip");
        }
        let prefix = prefix
            .map(str::trim)
            .filter(|value| !value.is_empty())
            .map(ToOwned::to_owned);
        let requested_cwd = cwd
            .map(str::trim)
            .filter(|value| !value.is_empty())
            .map(ToOwned::to_owned);
        let cwd =
            normalize_remote_attach_cwd(&ssh_target, prefix.as_deref(), requested_cwd.as_deref());
        let title = title_hint
            .map(str::trim)
            .filter(|value| !value.is_empty())
            .map(ToOwned::to_owned)
            .unwrap_or_else(|| {
                let fallback = ssh_target
                    .rsplit('@')
                    .next()
                    .unwrap_or(ssh_target.as_str())
                    .to_string();
                live_session_default_title(SessionKind::SshShell, cwd.as_deref(), &fallback)
            });
        let target_label = self
            .ssh_targets
            .iter()
            .find(|existing| {
                existing.kind == SessionKind::SshShell
                    && existing.ssh_target == ssh_target
                    && existing.prefix == prefix
            })
            .map(|existing| existing.label.trim().to_string())
            .filter(|label| !label.is_empty())
            .unwrap_or_else(|| {
                ssh_machine_label(&SshConnectTarget {
                    label: String::new(),
                    kind: SessionKind::SshShell,
                    ssh_target: ssh_target.clone(),
                    prefix: prefix.clone(),
                    cwd: cwd.clone(),
                })
            });
        let target = SshConnectTarget {
            label: target_label,
            kind: SessionKind::SshShell,
            ssh_target,
            prefix,
            cwd,
        };
        self.upsert_ssh_target(&target);
        let resolved_remote_launch = self.resolve_ssh_shell_remote_launch(&target)?;
        let uuid = Uuid::new_v4().to_string();
        let key = format!("live::{uuid}");
        self.insert_live_session(&key, &uuid, SessionKind::SshShell, &target, Some(title));
        if let Some((remote_binary, remote_deploy_state)) = resolved_remote_launch {
            self.configure_remote_ssh_shell_live_session(
                &key,
                &target,
                &remote_binary,
                remote_deploy_state,
            );
        }
        Ok(key)
    }

    pub fn start_remote_codex_session(
        &mut self,
        target: &str,
        prefix: Option<&str>,
        cwd: Option<&str>,
        title_hint: Option<&str>,
    ) -> anyhow::Result<String> {
        let ssh_target = canonicalize_ssh_target_alias(target);
        if ssh_target.is_empty() {
            anyhow::bail!("enter an SSH target such as dev, pi@raspberry, or user@ip");
        }
        let prefix = prefix
            .map(str::trim)
            .filter(|value| !value.is_empty())
            .map(ToOwned::to_owned);
        let requested_cwd = cwd
            .map(str::trim)
            .filter(|value| !value.is_empty())
            .map(ToOwned::to_owned);
        let cwd =
            normalize_remote_attach_cwd(&ssh_target, prefix.as_deref(), requested_cwd.as_deref());
        let machine_key = machine_key_from_ssh_target(&ssh_target);
        let target_label = self
            .ssh_targets
            .iter()
            .find(|existing| existing.ssh_target == ssh_target && existing.prefix == prefix)
            .map(|existing| existing.label.trim().to_string())
            .filter(|label| !label.is_empty())
            .unwrap_or_else(|| {
                ssh_machine_label(&SshConnectTarget {
                    label: String::new(),
                    kind: SessionKind::SshShell,
                    ssh_target: ssh_target.clone(),
                    prefix: prefix.clone(),
                    cwd: cwd.clone(),
                })
            });
        let target = SshConnectTarget {
            label: target_label,
            kind: SessionKind::SshShell,
            ssh_target: ssh_target.clone(),
            prefix,
            cwd,
        };
        self.upsert_ssh_target(&target);
        self.ensure_remote_machine_stub(&target);
        let uuid = Uuid::new_v4().to_string();
        let key = remote_scanned_session_path(&machine_key, &uuid);
        let title = title_hint
            .map(str::trim)
            .filter(|value| !value.is_empty())
            .map(ToOwned::to_owned)
            .unwrap_or_else(|| {
                live_session_default_title(
                    SessionKind::Codex,
                    target.cwd.as_deref(),
                    &ssh_machine_label(&target),
                )
            });
        let (remote_binary, remote_deploy_state) = self
            .cached_remote_launch_for_target(&target.ssh_target, target.prefix.as_deref())
            .unwrap_or_else(|| {
                (
                    preferred_remote_binary_fallback(),
                    RemoteDeployState::Planned,
                )
            });
        let mut session = build_live_session(
            &uuid,
            SessionKind::Codex,
            &target,
            self.backend,
            self.theme,
            self.ghostty_host.bridge_enabled,
        );
        configure_remote_new_codex_live_session(
            &mut session,
            &key,
            &uuid,
            &title,
            &target,
            &remote_binary,
            remote_deploy_state,
            target.cwd.as_deref(),
            self.theme,
        );
        self.sessions.insert(key.clone(), session);
        self.live_session_order.retain(|existing| existing != &key);
        self.live_session_order.insert(0, key.clone());
        self.active_session_path = Some(key.clone());
        self.active_view_mode = WorkspaceViewMode::Terminal;
        self.request_terminal_launch_for_active();
        Ok(key)
    }

    /// Start a NEW remote Claude Code session over a direct SSH PTY. Mirrors
    /// `open_remote_cc_session` (which RESUMES an existing transcript) but
    /// assigns the session id up front and launches `claude --session-id <uuid>`.
    /// Claude Code adopts the caller-provided id as its real transcript id
    /// (verified: a fresh `--session-id` writes `~/.claude/projects/.../<id>.jsonl`),
    /// so the yggterm row id IS the authoritative CLI session id — no UUIDv4
    /// drift and no rebind poll, unlike Codex / local Claude Code. See
    /// [[finding-uuidv4-codex-session-drift]]. This is the lightweight direct-SSH
    /// model (not the daemon-runtime bridge Codex uses), consistent with how
    /// remote Claude Code resume already works.
    pub fn start_remote_claude_session(
        &mut self,
        target: &str,
        prefix: Option<&str>,
        cwd: Option<&str>,
        title_hint: Option<&str>,
    ) -> anyhow::Result<String> {
        let ssh_target = canonicalize_ssh_target_alias(target);
        if ssh_target.is_empty() {
            anyhow::bail!("enter an SSH target such as dev, pi@raspberry, or user@ip");
        }
        let prefix = prefix
            .map(str::trim)
            .filter(|value| !value.is_empty())
            .map(ToOwned::to_owned);
        let requested_cwd = cwd
            .map(str::trim)
            .filter(|value| !value.is_empty())
            .map(ToOwned::to_owned);
        let cwd =
            normalize_remote_attach_cwd(&ssh_target, prefix.as_deref(), requested_cwd.as_deref());
        let machine_key = machine_key_from_ssh_target(&ssh_target);
        let target_label = self
            .ssh_targets
            .iter()
            .find(|existing| existing.ssh_target == ssh_target && existing.prefix == prefix)
            .map(|existing| existing.label.trim().to_string())
            .filter(|label| !label.is_empty())
            .unwrap_or_else(|| {
                ssh_machine_label(&SshConnectTarget {
                    label: String::new(),
                    kind: SessionKind::SshShell,
                    ssh_target: ssh_target.clone(),
                    prefix: prefix.clone(),
                    cwd: cwd.clone(),
                })
            });
        // Register the machine/target stub (kind-agnostic) so the row is anchored
        // to a known remote machine, exactly as the Codex start path does.
        let registry_target = SshConnectTarget {
            label: target_label.clone(),
            kind: SessionKind::SshShell,
            ssh_target: ssh_target.clone(),
            prefix: prefix.clone(),
            cwd: cwd.clone(),
        };
        self.upsert_ssh_target(&registry_target);
        self.ensure_remote_machine_stub(&registry_target);

        let cc_target = SshConnectTarget {
            label: target_label.clone(),
            kind: SessionKind::ClaudeCode,
            ssh_target: ssh_target.clone(),
            prefix: prefix.clone(),
            cwd: cwd.clone(),
        };
        let uuid = Uuid::new_v4().to_string();
        let session_path = remote_cc_session_path(&machine_key, &uuid);
        let cwd_display = cwd.clone().unwrap_or_default();
        let cwd_prefix = if cwd_display.trim().is_empty() {
            String::new()
        } else {
            format!("cd {} && ", shell_single_quote(&cwd_display))
        };
        let claude_extra_args = legacy_claude_code_extra_args();
        let inner = remote_cc_launch_inner_command(&cwd_prefix, &claude_extra_args, &uuid);
        let launch_command = remote_ssh_shell_command(&ssh_target, prefix.as_deref(), &inner);
        let title = title_hint
            .map(str::trim)
            .filter(|value| !value.is_empty())
            .map(ToOwned::to_owned)
            .unwrap_or_else(|| {
                live_session_default_title(
                    SessionKind::ClaudeCode,
                    cwd.as_deref(),
                    &ssh_machine_label(&cc_target),
                )
            });

        let mut session = build_live_session(
            &uuid,
            SessionKind::ClaudeCode,
            &cc_target,
            self.backend,
            self.theme,
            self.ghostty_host.bridge_enabled,
        );
        session.session_path = session_path.clone();
        session.id = uuid.clone();
        session.title = title.clone();
        session.source = SessionSource::LiveSsh;
        session.host_label = target_label;
        session.launch_phase = TerminalLaunchPhase::RemoteBootstrap;
        session.ssh_target = Some(ssh_target.clone());
        session.ssh_prefix = prefix.clone();
        session.launch_command = launch_command;
        session.terminal_lines = vec![
            format!("Queue new remote Claude Code session {uuid}"),
            format!("Target host: {ssh_target}"),
            format!(
                "Workspace: {}",
                if cwd_display.trim().is_empty() {
                    "<unknown>".to_string()
                } else {
                    cwd_display.clone()
                }
            ),
        ];
        if let Some(cwd) = cwd.as_deref() {
            upsert_session_metadata(&mut session.metadata, "Cwd", cwd.to_string());
        }
        upsert_session_metadata(&mut session.metadata, "Host", ssh_target.clone());
        upsert_session_metadata(&mut session.metadata, "UUID", uuid.clone());
        upsert_session_metadata(&mut session.metadata, "Claude Code Session", uuid.clone());
        upsert_session_metadata(
            &mut session.metadata,
            "Restore",
            format!("ssh {ssh_target} '{cwd_prefix}claude{claude_extra_args} --resume {uuid}'"),
        );

        self.sessions.insert(session_path.clone(), session);
        self.live_session_order
            .retain(|existing| existing != &session_path);
        self.live_session_order.insert(0, session_path.clone());
        self.active_session_path = Some(session_path.clone());
        self.active_view_mode = WorkspaceViewMode::Terminal;
        Ok(session_path)
    }

    pub(crate) fn is_loopback_remote_target(target: &SshConnectTarget) -> bool {
        is_loopback_ssh_target(&target.ssh_target)
    }

    pub(crate) fn scan_remote_machine_refresh(
        target: &SshConnectTarget,
    ) -> RemoteMachineRefreshScan {
        if let Ok(home) = resolve_yggterm_home() {
            append_trace_event(
                &home,
                "server",
                "remote_machine",
                "refresh_begin",
                serde_json::json!({
                    "ssh_target": target.ssh_target.clone(),
                    "prefix": target.prefix.clone(),
                }),
            );
        }
        let resolved_remote_launch =
            resolve_remote_yggterm_binary(&target.ssh_target, target.prefix.as_deref()).ok();
        let remote_binary_expr = resolved_remote_launch
            .as_ref()
            .map(|(binary_expr, _)| binary_expr.clone());
        let remote_deploy_state = resolved_remote_launch
            .map(|(_, deploy_state)| deploy_state)
            .unwrap_or(RemoteDeployState::Planned);
        RemoteMachineRefreshScan {
            remote_binary_expr,
            remote_deploy_state,
            scan_result: scan_remote_machine_sessions(target),
        }
    }

    pub(crate) fn apply_remote_machine_refresh_scan(
        &mut self,
        target: &SshConnectTarget,
        scan: RemoteMachineRefreshScan,
    ) -> anyhow::Result<()> {
        let machine_key = machine_key_from_ssh_target(&target.ssh_target);
        let label = ssh_machine_label(target);
        let entry_ix = self.ensure_remote_machine_stub(target);
        match scan.scan_result {
            Ok(mut sessions) => {
                sessions.sort_by(|left, right| {
                    right
                        .modified_epoch
                        .cmp(&left.modified_epoch)
                        .then_with(|| right.started_at.cmp(&left.started_at))
                });
                sessions = overlay_mirrored_remote_sessions(&machine_key, &sessions);
                if let Err(mirror_error) = mirror_remote_machine_sessions(&machine_key, &sessions) {
                    warn!(machine_key, error=%mirror_error, "failed to mirror remote machine sessions locally");
                }
                self.remote_machines[entry_ix] = RemoteMachineSnapshot {
                    machine_key,
                    label,
                    ssh_target: target.ssh_target.clone(),
                    prefix: target.prefix.clone(),
                    remote_binary_expr: scan.remote_binary_expr,
                    remote_deploy_state: scan.remote_deploy_state,
                    health: RemoteMachineHealth::Healthy,
                    sessions,
                };
                let refreshed_machine_key = self.remote_machines[entry_ix].machine_key.clone();
                let pruned_live_sessions = self
                    .prune_stale_temporary_remote_live_sessions_after_scan(&refreshed_machine_key);
                if let Ok(home) = resolve_yggterm_home() {
                    append_trace_event(
                        &home,
                        "server",
                        "remote_machine",
                        "refresh_end",
                        serde_json::json!({
                            "ssh_target": target.ssh_target,
                            "machine_key": self.remote_machines[entry_ix].machine_key,
                            "health": "healthy",
                            "session_count": self.remote_machines[entry_ix].sessions.len(),
                            "pruned_temporary_live_sessions": pruned_live_sessions,
                        }),
                    );
                }
                Ok(())
            }
            Err(error) => {
                let existing_sessions = if self.remote_machines[entry_ix].sessions.is_empty() {
                    load_remote_machine_sessions_from_mirror(&machine_key).unwrap_or_default()
                } else {
                    overlay_mirrored_remote_sessions(
                        &machine_key,
                        &self.remote_machines[entry_ix].sessions,
                    )
                };
                self.remote_machines[entry_ix] = RemoteMachineSnapshot {
                    machine_key,
                    label,
                    ssh_target: target.ssh_target.clone(),
                    prefix: target.prefix.clone(),
                    remote_binary_expr: scan.remote_binary_expr,
                    remote_deploy_state: scan.remote_deploy_state,
                    health: if existing_sessions.is_empty() {
                        RemoteMachineHealth::Offline
                    } else {
                        RemoteMachineHealth::Cached
                    },
                    sessions: existing_sessions,
                };
                if let Ok(home) = resolve_yggterm_home() {
                    append_trace_event(
                        &home,
                        "server",
                        "remote_machine",
                        "refresh_error",
                        serde_json::json!({
                            "ssh_target": target.ssh_target,
                            "machine_key": self.remote_machines[entry_ix].machine_key,
                            "health": format!("{:?}", self.remote_machines[entry_ix].health),
                            "error": error.to_string(),
                        }),
                    );
                }
                Err(error)
            }
        }
    }

    pub fn refresh_remote_machine_for_ssh_target(
        &mut self,
        target: &SshConnectTarget,
    ) -> anyhow::Result<()> {
        if Self::is_loopback_remote_target(target) {
            return Ok(());
        }
        let scan = Self::scan_remote_machine_refresh(target);
        self.apply_remote_machine_refresh_scan(target, scan)
    }

    pub fn refresh_remote_machine_by_key(&mut self, machine_key: &str) -> anyhow::Result<()> {
        let machine_key = normalize_machine_key(machine_key);
        let target = self.remote_target_for_machine_key(&machine_key)?;
        self.refresh_remote_machine_for_ssh_target(&target)
    }

    fn prune_stale_temporary_remote_live_sessions_after_scan(
        &mut self,
        machine_key: &str,
    ) -> usize {
        let normalized_machine_key = normalize_machine_key(machine_key);
        let stale_paths = self
            .live_session_order
            .iter()
            .filter_map(|key| {
                let session = self.sessions.get(key)?;
                let (raw_session_machine_key, _) =
                    parse_remote_scanned_session_path(&session.session_path)?;
                if normalize_machine_key(raw_session_machine_key) != normalized_machine_key {
                    return None;
                }
                if session.source != SessionSource::LiveSsh
                    || !session_is_temporary_update_restore(session)
                    || session_keep_alive(session)
                    || remote_live_session_starts_new_codex(session)
                    || remote_scanned_session_path_is_live(
                        &self.remote_machines,
                        &session.session_path,
                    )
                {
                    return None;
                }
                Some((key.clone(), session.session_path.clone()))
            })
            .collect::<Vec<_>>();
        if stale_paths.is_empty() {
            return 0;
        }
        let stale_keys = stale_paths
            .iter()
            .map(|(key, _)| key.clone())
            .collect::<HashSet<_>>();
        self.live_session_order
            .retain(|existing| !stale_keys.contains(existing));
        for (key, session_path) in &stale_paths {
            self.sessions.remove(key);
            if self
                .active_session_path
                .as_deref()
                .is_some_and(|active| active == key || active == session_path)
            {
                self.active_session_path = None;
                self.active_view_mode = WorkspaceViewMode::Rendered;
            }
        }
        if let Ok(home) = resolve_yggterm_home() {
            append_trace_event(
                &home,
                "server",
                "remote_machine",
                "prune_temporary_stale_live_sessions",
                serde_json::json!({
                    "machine_key": normalized_machine_key,
                    "session_count": stale_paths.len(),
                    "session_paths": stale_paths
                        .iter()
                        .map(|(_, session_path)| session_path)
                        .collect::<Vec<_>>(),
                }),
            );
        }
        self.normalize_active_view_mode();
        stale_paths.len()
    }

    fn promote_remote_machine_health(
        &mut self,
        machine_key: &str,
        target: Option<&SshConnectTarget>,
        remote_binary_expr: Option<String>,
        remote_deploy_state: Option<RemoteDeployState>,
    ) {
        let machine_key = normalize_machine_key(machine_key);
        let entry_ix = if let Some(target) = target {
            self.ensure_remote_machine_stub(target)
        } else if let Some(entry_ix) = self
            .remote_machines
            .iter()
            .position(|machine| machine.machine_key == machine_key)
        {
            entry_ix
        } else {
            return;
        };
        let machine = &mut self.remote_machines[entry_ix];
        if let Some(target) = target {
            machine.label = ssh_machine_label(target);
            machine.ssh_target = target.ssh_target.clone();
            machine.prefix = target.prefix.clone();
        }
        if let Some(remote_binary_expr) = remote_binary_expr {
            machine.remote_binary_expr = Some(remote_binary_expr);
        }
        if let Some(remote_deploy_state) = remote_deploy_state {
            machine.remote_deploy_state = remote_deploy_state;
        }
        machine.health = RemoteMachineHealth::Healthy;
    }

    pub fn ensure_managed_cli_for_session_path(
        &self,
        path: &str,
    ) -> anyhow::Result<Option<String>> {
        let Some(key) = self.resolve_session_storage_key(path) else {
            return Ok(None);
        };
        let Some(session) = self.sessions.get(key) else {
            return Ok(None);
        };
        if path.starts_with("remote-session://") {
            // Remote session attach must stay fast. Background machine refreshes keep the managed
            // Codex toolchain current; PTY restore should not block on a synchronous SSH upgrade.
            return Ok(None);
        }
        let Some(tool) = ManagedCliTool::from_session_kind(session.kind) else {
            return Ok(None);
        };
        let status = ensure_local_managed_cli(tool)?;
        let install_attempted = status.action == "installed";
        Ok(Some(summarize_managed_cli_report(
            "local",
            &ManagedCliRefreshReport {
                scope: "local".to_string(),
                background: false,
                statuses: vec![status],
                skipped_recently: false,
                ttl_remaining_ms: None,
                install_attempted,
                install_deferred: false,
            },
        )))
    }

    pub fn refresh_managed_cli(
        &self,
        machine_key: Option<&str>,
        background: bool,
    ) -> anyhow::Result<String> {
        let (scope, report) = match machine_key.map(str::trim).filter(|value| !value.is_empty()) {
            Some(machine_key) => {
                let machine_key = normalize_machine_key(machine_key);
                let target = self.remote_target_for_machine_key(&machine_key)?;
                let report = refresh_remote_managed_cli(
                    &target.ssh_target,
                    target.prefix.as_deref(),
                    background,
                )?;
                (machine_key, report)
            }
            None => ("local".to_string(), refresh_local_managed_cli(background)?),
        };
        Ok(summarize_managed_cli_report(&scope, &report))
    }

    pub fn queue_background_managed_cli_refresh(
        &self,
        machine_key: Option<&str>,
    ) -> anyhow::Result<String> {
        match machine_key.map(str::trim).filter(|value| !value.is_empty()) {
            Some(machine_key) => {
                let machine_key = normalize_machine_key(machine_key);
                let target = self.remote_target_for_machine_key(&machine_key)?;
                let ssh_target = target.ssh_target.clone();
                let prefix = target.prefix.clone();
                let queued_scope = machine_key.clone();
                std::thread::spawn(move || {
                    if let Err(error) =
                        refresh_remote_managed_cli(&ssh_target, prefix.as_deref(), true)
                    {
                        warn!(
                            machine_key = %queued_scope,
                            ssh_target = %ssh_target,
                            error = %error,
                            "background managed cli refresh failed"
                        );
                    }
                });
                Ok(format!("queued managed cli refresh for {machine_key}"))
            }
            None => {
                std::thread::spawn(|| {
                    if let Err(error) = refresh_local_managed_cli(true) {
                        warn!(error = %error, "background managed cli refresh failed");
                    }
                });
                Ok("queued managed cli refresh for local".to_string())
            }
        }
    }

    pub(crate) fn remote_target_for_machine_key(
        &self,
        machine_key: &str,
    ) -> anyhow::Result<SshConnectTarget> {
        let machine_key = normalize_machine_key(machine_key);
        self.ssh_targets
            .iter()
            .find(|target| machine_key_from_ssh_target(&target.ssh_target) == machine_key)
            .cloned()
            .or_else(|| {
                self.remote_machines
                    .iter()
                    .find(|machine| machine.machine_key == machine_key)
                    .map(|machine| SshConnectTarget {
                        label: machine.label.clone(),
                        kind: SessionKind::SshShell,
                        ssh_target: machine.ssh_target.clone(),
                        prefix: machine.prefix.clone(),
                        cwd: None,
                    })
            })
            .ok_or_else(|| anyhow::anyhow!("remote machine not found: {machine_key}"))
    }

    fn cached_remote_launch_for_target(
        &self,
        ssh_target: &str,
        prefix: Option<&str>,
    ) -> Option<(String, RemoteDeployState)> {
        self.remote_machines
            .iter()
            .find(|machine| {
                machine.ssh_target == ssh_target
                    && machine.prefix.as_deref() == prefix
                    && machine.health == RemoteMachineHealth::Healthy
            })
            .and_then(|machine| {
                machine
                    .remote_binary_expr
                    .clone()
                    .map(|binary_expr| (binary_expr, machine.remote_deploy_state))
            })
    }

    pub fn open_remote_scanned_session(
        &mut self,
        machine_key: &str,
        session_id: &str,
        cwd: Option<&str>,
        title_hint: Option<&str>,
    ) -> anyhow::Result<String> {
        self.open_remote_scanned_session_with_view(machine_key, session_id, cwd, title_hint, None)
    }

    pub fn open_remote_scanned_session_with_view(
        &mut self,
        machine_key: &str,
        session_id: &str,
        cwd: Option<&str>,
        title_hint: Option<&str>,
        view_mode: Option<WorkspaceViewMode>,
    ) -> anyhow::Result<String> {
        let launch_terminal = view_mode != Some(WorkspaceViewMode::Rendered);
        let machine_key = normalize_machine_key(machine_key);
        if let Ok(home) = resolve_yggterm_home() {
            append_trace_event(
                &home,
                "server",
                "remote_session",
                "open",
                serde_json::json!({
                    "machine_key": machine_key.clone(),
                    "session_id": session_id,
                    "cwd": cwd,
                }),
            );
        }
        let machine = self
            .remote_machines
            .iter()
            .find(|machine| machine.machine_key == machine_key)
            .cloned()
            .ok_or_else(|| anyhow::anyhow!("remote machine not found: {machine_key}"))?;
        let session_path = remote_scanned_session_path(&machine_key, session_id);
        let target = SshConnectTarget {
            label: machine.label.clone(),
            kind: SessionKind::SshShell,
            ssh_target: machine.ssh_target.clone(),
            prefix: machine.prefix.clone(),
            cwd: cwd.map(ToOwned::to_owned),
        };
        if !launch_terminal {
            let scanned = machine
                .sessions
                .iter()
                .find(|scanned| scanned.session_id == session_id)
                .cloned();
            let mut applied_head_preview = false;
            let already_live = self
                .sessions
                .get(&session_path)
                .is_some_and(|session| session.source == SessionSource::LiveSsh)
                && self
                    .live_session_order
                    .iter()
                    .any(|existing| existing == &session_path);
            if let Some(scanned) = scanned.as_ref() {
                if already_live {
                    if let Some(session) = self.sessions.get_mut(&session_path) {
                        apply_remote_scanned_session_preview(
                            session,
                            scanned,
                            &machine.label,
                            &target.ssh_target,
                        );
                    }
                    self.active_session_path = Some(session_path.clone());
                    self.active_view_mode = WorkspaceViewMode::Terminal;
                    self.normalize_active_view_mode();
                    return Ok(session_path);
                } else {
                    let mut session = synthesize_remote_scanned_preview_session_view(
                        &machine,
                        scanned,
                        self.backend,
                        self.theme,
                        self.ghostty_host.bridge_enabled,
                    );
                    mark_session_preview_loading(&mut session);
                    applied_head_preview =
                        try_apply_remote_preview_head_payload(&mut session, &target, scanned);
                    self.sessions.insert(session_path.clone(), session);
                    self.live_session_order
                        .retain(|existing| existing != &session_path);
                }
            }
            if applied_head_preview {
                self.promote_remote_machine_health(
                    &machine_key,
                    Some(&target),
                    machine.remote_binary_expr.clone(),
                    Some(machine.remote_deploy_state),
                );
            }
            self.active_session_path = Some(session_path.clone());
            self.active_view_mode = WorkspaceViewMode::Rendered;
            return Ok(session_path);
        }
        let cached_remote_launch =
            self.cached_remote_launch_for_target(&target.ssh_target, target.prefix.as_deref());
        let resolved_remote_launch = if launch_terminal && cached_remote_launch.is_none() {
            resolve_remote_yggterm_binary(&target.ssh_target, target.prefix.as_deref()).ok()
        } else {
            None
        };
        let (remote_binary, remote_deploy_state) = resolved_remote_launch
            .clone()
            .or(cached_remote_launch.clone())
            .unwrap_or_else(|| {
                if launch_terminal {
                    (
                        preferred_remote_binary_fallback(),
                        RemoteDeployState::Planned,
                    )
                } else {
                    machine
                        .remote_binary_expr
                        .clone()
                        .map(|binary_expr| (binary_expr, machine.remote_deploy_state))
                        .unwrap_or_else(|| {
                            (
                                preferred_remote_binary_fallback(),
                                machine.remote_deploy_state,
                            )
                        })
                }
            });
        if let Some((remote_binary_expr, remote_deploy_state)) = resolved_remote_launch {
            self.promote_remote_machine_health(
                &machine_key,
                Some(&target),
                Some(remote_binary_expr),
                Some(remote_deploy_state),
            );
        }
        let resolved_title = title_hint
            .map(ToOwned::to_owned)
            .unwrap_or_else(|| short_session_id(session_id));
        if self.sessions.contains_key(&session_path) {
            let mut applied_head_preview = false;
            if let Some(session) = self.sessions.get_mut(&session_path) {
                configure_remote_resume_live_session(
                    session,
                    &session_path,
                    session_id,
                    &resolved_title,
                    &target,
                    &remote_binary,
                    remote_deploy_state,
                    cwd,
                    self.theme,
                );
                if let Some(scanned) = machine
                    .sessions
                    .iter()
                    .find(|scanned| scanned.session_id == session_id)
                {
                    apply_remote_scanned_session_preview(
                        session,
                        scanned,
                        &machine.label,
                        &target.ssh_target,
                    );
                    if !launch_terminal {
                        mark_session_preview_loading(session);
                        applied_head_preview =
                            try_apply_remote_preview_head_payload(session, &target, scanned);
                    }
                }
            }
            if applied_head_preview {
                self.promote_remote_machine_health(
                    &machine_key,
                    Some(&target),
                    machine.remote_binary_expr.clone(),
                    Some(machine.remote_deploy_state),
                );
            }
            if launch_terminal {
                self.live_session_order
                    .retain(|existing| existing != &session_path);
                self.live_session_order.insert(0, session_path.clone());
                self.focus_live_session(&session_path);
            } else {
                self.active_session_path = Some(session_path.clone());
                self.active_view_mode = WorkspaceViewMode::Rendered;
            }
            return Ok(session_path);
        }
        self.insert_live_session_with_launch(
            &session_path,
            session_id,
            SessionKind::Codex,
            &target,
            Some(resolved_title.clone()),
            launch_terminal,
        );
        let mut applied_head_preview = false;
        if let Some(session) = self.sessions.get_mut(&session_path) {
            configure_remote_resume_live_session(
                session,
                &session_path,
                session_id,
                &resolved_title,
                &target,
                &remote_binary,
                remote_deploy_state,
                cwd,
                self.theme,
            );
            if let Some(scanned) = machine
                .sessions
                .iter()
                .find(|scanned| scanned.session_id == session_id)
            {
                apply_remote_scanned_session_preview(
                    session,
                    scanned,
                    &machine.label,
                    &target.ssh_target,
                );
                if !launch_terminal {
                    mark_session_preview_loading(session);
                    applied_head_preview =
                        try_apply_remote_preview_head_payload(session, &target, scanned);
                }
            }
        }
        if applied_head_preview {
            self.promote_remote_machine_health(
                &machine_key,
                Some(&target),
                machine.remote_binary_expr.clone(),
                Some(machine.remote_deploy_state),
            );
        }
        if launch_terminal {
            self.focus_live_session(&session_path);
        } else {
            self.active_session_path = Some(session_path.clone());
            self.active_view_mode = WorkspaceViewMode::Rendered;
        }
        Ok(session_path)
    }

    pub fn stage_remote_scanned_session_with_view(
        &mut self,
        machine_key: &str,
        session_id: &str,
        view_mode: WorkspaceViewMode,
    ) -> Option<String> {
        let machine_key = normalize_machine_key(machine_key);
        let machine = self
            .remote_machines
            .iter()
            .find(|machine| machine.machine_key == machine_key)?
            .clone();
        let scanned = machine
            .sessions
            .iter()
            .find(|session| session.session_id == session_id)?
            .clone();
        let session_path = scanned.session_path.clone();
        let mut staged = if view_mode == WorkspaceViewMode::Terminal {
            synthesize_remote_scanned_session_view(
                &machine,
                &scanned,
                self.backend,
                self.theme,
                self.ghostty_host.bridge_enabled,
            )
        } else {
            synthesize_remote_scanned_preview_session_view(
                &machine,
                &scanned,
                self.backend,
                self.theme,
                self.ghostty_host.bridge_enabled,
            )
        };
        if view_mode == WorkspaceViewMode::Rendered {
            clear_session_preview_for_loading(&mut staged);
        }
        self.sessions.insert(session_path.clone(), staged);
        if view_mode == WorkspaceViewMode::Terminal {
            if !self
                .live_session_order
                .iter()
                .any(|existing| existing == &session_path)
            {
                self.live_session_order.insert(0, session_path.clone());
            }
        } else {
            self.live_session_order
                .retain(|existing| existing != &session_path);
        }
        self.active_session_path = Some(session_path.clone());
        self.active_view_mode = view_mode;
        Some(session_path)
    }

