fn app_control_state_response(home: &Path, timeout_ms: u64) -> anyhow::Result<AppControlResponse> {
    request_app_control(home, AppControlCommand::DescribeState, timeout_ms)
}

fn app_control_state_data<'a>(response: &'a AppControlResponse) -> anyhow::Result<&'a Value> {
    response
        .data
        .as_ref()
        .context("app-control state response did not include data")
}

fn json_f64(value: Option<&Value>) -> Option<f64> {
    value.and_then(Value::as_f64)
}

fn json_u32(value: Option<&Value>) -> Option<u32> {
    value
        .and_then(Value::as_u64)
        .and_then(|number| u32::try_from(number).ok())
}

#[derive(Debug, Clone)]
struct X11TerminalProbeContext {
    pid: u32,
    display: String,
    xauthority: Option<String>,
    session_path: String,
    x: i32,
    y: i32,
    scroll_x: i32,
    scroll_y: i32,
    before: Value,
}

fn terminal_host_probe_snapshot(host: &Value) -> Value {
    json!({
        "session_path": host.get("session_path").and_then(Value::as_str).unwrap_or_default(),
        "host_stdin_enabled": host.get("host_stdin_enabled").and_then(Value::as_bool),
        "helper_textarea_focused": host.get("helper_textarea_has_focus").and_then(Value::as_bool)
            .or_else(|| host.get("helper_textarea_focused").and_then(Value::as_bool)),
        "host_has_active_element": host.get("host_has_active_element").and_then(Value::as_bool),
        "viewport_y": host.get("viewport_y").and_then(Value::as_i64),
        "base_y": host.get("base_y").and_then(Value::as_i64),
        "viewport_scroll_top": host.get("viewport_scroll_top").and_then(Value::as_f64),
        "scrollback_expected": host.get("scrollback_expected").and_then(Value::as_bool),
        "last_raw_payload_line_count": host.get("last_raw_payload_line_count").and_then(Value::as_u64),
        "cols": host.get("cols").and_then(Value::as_u64),
        "rows": host.get("rows").and_then(Value::as_u64),
        "text_head": host.get("text_head")
            .or_else(|| host.get("text_sample"))
            .and_then(Value::as_str)
            .unwrap_or_default(),
        "text_tail": host.get("text_tail")
            .or_else(|| host.get("buffer_text_sample"))
            .or_else(|| host.get("text_sample"))
            .and_then(Value::as_str)
            .unwrap_or_default(),
        "cursor_line_text": host.get("cursor_line_text")
            .or_else(|| host.get("cursor_row_text"))
            .and_then(Value::as_str)
            .unwrap_or_default(),
        "data_event_count": host.get("data_event_count").and_then(Value::as_u64),
        "render_event_count": host.get("render_event_count").and_then(Value::as_u64),
        "write_bridge_flush_count": host.get("write_bridge_flush_count").and_then(Value::as_u64),
        "write_command_count": host.get("write_command_count").and_then(Value::as_u64),
        "wheel_event_count": host.get("wheel_event_count").and_then(Value::as_u64),
        "scroll_event_count": host.get("scroll_event_count").and_then(Value::as_u64),
        "last_data_event_at_ms": host.get("last_data_event_at_ms").and_then(Value::as_u64),
        "last_render_event_at_ms": host.get("last_render_event_at_ms").and_then(Value::as_u64),
        "last_write_queued_at_ms": host.get("last_write_queued_at_ms").and_then(Value::as_u64),
        "last_write_flush_started_at_ms": host.get("last_write_flush_started_at_ms").and_then(Value::as_u64),
        "last_write_callback_at_ms": host.get("last_write_callback_at_ms").and_then(Value::as_u64),
    })
}

fn terminal_probe_focus_ready(snapshot: &Value) -> bool {
    let host_stdin_enabled = snapshot
        .get("host_stdin_enabled")
        .and_then(Value::as_bool)
        .unwrap_or(false);
    let helper_focused = snapshot
        .get("helper_textarea_focused")
        .and_then(Value::as_bool)
        .unwrap_or(false);
    let host_has_active_element = snapshot
        .get("host_has_active_element")
        .and_then(Value::as_bool)
        .unwrap_or(false);
    host_stdin_enabled && (helper_focused || host_has_active_element)
}

fn terminal_probe_snapshot_timeout_ms(timeout_ms: u64) -> u64 {
    timeout_ms.clamp(750, 4_000)
}

fn terminal_probe_snapshot_changed(before: &Value, after: &Value, data: &str) -> bool {
    let before_text = before
        .get("text_tail")
        .and_then(Value::as_str)
        .unwrap_or_default();
    let after_text = after
        .get("text_tail")
        .and_then(Value::as_str)
        .unwrap_or_default();
    let before_cursor = before
        .get("cursor_line_text")
        .and_then(Value::as_str)
        .unwrap_or_default();
    let after_cursor = after
        .get("cursor_line_text")
        .and_then(Value::as_str)
        .unwrap_or_default();
    if !data.is_empty()
        && (after_text.contains(data) || after_cursor.contains(data))
        && (after_text != before_text || after_cursor != before_cursor)
    {
        return true;
    }
    let before_data_events = before
        .get("data_event_count")
        .and_then(Value::as_u64)
        .unwrap_or(0);
    let after_data_events = after
        .get("data_event_count")
        .and_then(Value::as_u64)
        .unwrap_or(0);
    if after_data_events > before_data_events {
        return true;
    }
    let before_write_commands = before
        .get("write_command_count")
        .and_then(Value::as_u64)
        .unwrap_or(0);
    let after_write_commands = after
        .get("write_command_count")
        .and_then(Value::as_u64)
        .unwrap_or(0);
    if after_write_commands > before_write_commands {
        return true;
    }
    let before_last_write = before
        .get("last_write_queued_at_ms")
        .and_then(Value::as_u64)
        .unwrap_or(0);
    let after_last_write = after
        .get("last_write_queued_at_ms")
        .and_then(Value::as_u64)
        .unwrap_or(0);
    if after_last_write > before_last_write {
        return true;
    }
    after_text != before_text || after_cursor != before_cursor
}

fn terminal_probe_i64_field(snapshot: &Value, key: &str) -> Option<i64> {
    snapshot.get(key).and_then(|value| {
        value
            .as_i64()
            .or_else(|| value.as_u64().and_then(|number| i64::try_from(number).ok()))
    })
}

fn terminal_probe_f64_field(snapshot: &Value, key: &str) -> Option<f64> {
    snapshot.get(key).and_then(|value| {
        value
            .as_f64()
            .or_else(|| value.as_i64().map(|number| number as f64))
            .or_else(|| value.as_u64().map(|number| number as f64))
    })
}

fn terminal_scroll_probe_snapshot_can_move(snapshot: &Value, lines: i32) -> bool {
    if lines == 0 {
        return false;
    }
    let viewport_y = terminal_probe_i64_field(snapshot, "viewport_y");
    let base_y = terminal_probe_i64_field(snapshot, "base_y");
    let scroll_top = terminal_probe_f64_field(snapshot, "viewport_scroll_top").unwrap_or(0.0);
    if lines < 0 {
        return viewport_y.map(|value| value > 0).unwrap_or(false) || scroll_top > 0.5;
    }
    if let (Some(viewport_y), Some(base_y)) = (viewport_y, base_y) {
        return viewport_y < base_y;
    }
    false
}

fn terminal_scroll_probe_snapshot_moved(before: &Value, after: &Value) -> bool {
    if terminal_probe_i64_field(before, "viewport_y")
        != terminal_probe_i64_field(after, "viewport_y")
    {
        return true;
    }
    let before_scroll = terminal_probe_f64_field(before, "viewport_scroll_top");
    let after_scroll = terminal_probe_f64_field(after, "viewport_scroll_top");
    if let (Some(before_scroll), Some(after_scroll)) = (before_scroll, after_scroll)
        && (before_scroll - after_scroll).abs() > 0.5
    {
        return true;
    }
    false
}

fn x11_keyboard_probe_requires_focused_retry(
    before: &Value,
    after: &Value,
    data: &str,
    press_enter: bool,
    press_tab: bool,
    press_ctrl_c: bool,
    press_ctrl_e: bool,
    press_ctrl_u: bool,
) -> bool {
    if !terminal_probe_snapshot_changed(before, after, data) {
        return true;
    }
    if data.is_empty() && (press_enter || press_tab || press_ctrl_c || press_ctrl_e || press_ctrl_u)
    {
        return true;
    }
    false
}

fn active_terminal_probe_context(
    home: &Path,
    session_path: &str,
    timeout_ms: u64,
) -> anyhow::Result<X11TerminalProbeContext> {
    let response = app_control_state_response(home, timeout_ms)?;
    let data = app_control_state_data(&response)?;
    let active_session_path = data
        .get("active_session_path")
        .and_then(Value::as_str)
        .unwrap_or_default();
    if active_session_path != session_path {
        anyhow::bail!(
            "active session path mismatch for terminal probe: expected {session_path}, got {active_session_path}"
        );
    }
    let display = data
        .get("client_instance")
        .and_then(|value| value.get("display"))
        .and_then(Value::as_str)
        .filter(|value| !value.trim().is_empty())
        .context("active GUI client is not on an X11 display")?
        .to_string();
    let xauthority = data
        .get("client_instance")
        .and_then(|value| value.get("xauthority"))
        .and_then(Value::as_str)
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .map(ToOwned::to_owned);
    let viewport = data
        .get("viewport")
        .context("app-control state missing viewport payload")?;
    let host = viewport
        .get("terminal_hosts")
        .and_then(Value::as_array)
        .and_then(|hosts| {
            hosts.iter().find(|host| {
                host.get("session_path")
                    .and_then(Value::as_str)
                    .unwrap_or_default()
                    == session_path
            })
        })
        .context("active terminal host missing for terminal probe")?;
    let rect = host
        .get("viewport_rect")
        .or_else(|| host.get("host_rect"))
        .context("terminal probe host does not expose viewport geometry")?;
    let left = json_f64(rect.get("left")).context("terminal viewport left missing")?;
    let top = json_f64(rect.get("top")).context("terminal viewport top missing")?;
    let width = json_f64(rect.get("width")).context("terminal viewport width missing")?;
    let height = json_f64(rect.get("height")).context("terminal viewport height missing")?;
    let pid = json_u32(
        data.get("client_instance")
            .and_then(|value| value.get("pid")),
    )
    .unwrap_or(response.handled_by_pid);
    let prompt_rect = host
        .get("cursor_expected_rect")
        .or_else(|| host.get("cursor_row_rect"));
    let prompt_left = json_f64(prompt_rect.and_then(|value| value.get("left"))).unwrap_or(left);
    let prompt_top = json_f64(prompt_rect.and_then(|value| value.get("top"))).unwrap_or(top);
    let prompt_width =
        json_f64(prompt_rect.and_then(|value| value.get("width"))).unwrap_or(width.max(24.0));
    let prompt_height = json_f64(prompt_rect.and_then(|value| value.get("height"))).unwrap_or(24.0);
    let x = (prompt_left + prompt_width.clamp(8.0, 32.0) * 0.5).round() as i32;
    let y = (prompt_top + prompt_height * 0.5).round() as i32;
    let scroll_x = (left + (width * 0.5)).round() as i32;
    let scroll_y = (top + (height * 0.5)).round() as i32;
    Ok(X11TerminalProbeContext {
        pid,
        display,
        xauthority,
        session_path: session_path.to_string(),
        x,
        y,
        scroll_x,
        scroll_y,
        before: terminal_host_probe_snapshot(host),
    })
}

fn xdotool_command(display: &str, xauthority: Option<&str>) -> Command {
    let mut command = Command::new("xdotool");
    command.env("DISPLAY", display);
    if let Some(xauthority) = xauthority {
        command.env("XAUTHORITY", xauthority);
    }
    command
}

fn xdotool_key_for_char(ch: char) -> Option<&'static str> {
    match ch {
        'a' | 'A' => Some("a"),
        'b' | 'B' => Some("b"),
        'c' | 'C' => Some("c"),
        'd' | 'D' => Some("d"),
        'e' | 'E' => Some("e"),
        'f' | 'F' => Some("f"),
        'g' | 'G' => Some("g"),
        'h' | 'H' => Some("h"),
        'i' | 'I' => Some("i"),
        'j' | 'J' => Some("j"),
        'k' | 'K' => Some("k"),
        'l' | 'L' => Some("l"),
        'm' | 'M' => Some("m"),
        'n' | 'N' => Some("n"),
        'o' | 'O' => Some("o"),
        'p' | 'P' => Some("p"),
        'q' | 'Q' => Some("q"),
        'r' | 'R' => Some("r"),
        's' | 'S' => Some("s"),
        't' | 'T' => Some("t"),
        'u' | 'U' => Some("u"),
        'v' | 'V' => Some("v"),
        'w' | 'W' => Some("w"),
        'x' | 'X' => Some("x"),
        'y' | 'Y' => Some("y"),
        'z' | 'Z' => Some("z"),
        '0' => Some("0"),
        '1' => Some("1"),
        '2' => Some("2"),
        '3' => Some("3"),
        '4' => Some("4"),
        '5' => Some("5"),
        '6' => Some("6"),
        '7' => Some("7"),
        '8' => Some("8"),
        '9' => Some("9"),
        ' ' => Some("space"),
        '/' => Some("slash"),
        '-' => Some("minus"),
        '_' => Some("underscore"),
        '.' => Some("period"),
        ':' => Some("colon"),
        ',' => Some("comma"),
        _ => None,
    }
}

fn xdotool_key_args(window_id: Option<&str>, key: &str) -> Vec<String> {
    let mut args = vec!["key".to_string()];
    if let Some(window_id) = window_id {
        args.push("--window".to_string());
        args.push(window_id.to_string());
    }
    args.push("--clearmodifiers".to_string());
    args.push(key.to_string());
    args
}

fn xdotool_chord_args(window_id: Option<&str>, modifier: &str, key: &str) -> Vec<String> {
    let mut args = vec!["key".to_string()];
    if let Some(window_id) = window_id {
        args.push("--window".to_string());
        args.push(window_id.to_string());
    }
    args.push("--clearmodifiers".to_string());
    args.push(format!("{modifier}+{key}"));
    args
}

fn xdotool_type_args(window_id: Option<&str>, text: &str) -> Vec<String> {
    let mut args = vec!["type".to_string()];
    if let Some(window_id) = window_id {
        args.push("--window".to_string());
        args.push(window_id.to_string());
    }
    args.push("--clearmodifiers".to_string());
    args.push("--delay".to_string());
    args.push("8".to_string());
    args.push("--".to_string());
    args.push(text.to_string());
    args
}

fn xdotool_type_settle_delay_ms(text: &str) -> u64 {
    let chars = text.chars().count() as u64;
    let per_char_ms = 10;
    (120 + chars.saturating_mul(per_char_ms)).min(2_000)
}

fn run_xdotool_checked(
    display: &str,
    xauthority: Option<&str>,
    args: &[&str],
) -> anyhow::Result<String> {
    let output = xdotool_command(display, xauthority)
        .args(args)
        .output()
        .with_context(|| format!("running xdotool {}", args.join(" ")))?;
    if !output.status.success() {
        anyhow::bail!(
            "xdotool {} failed: {}",
            args.join(" "),
            String::from_utf8_lossy(&output.stderr).trim()
        );
    }
    Ok(String::from_utf8_lossy(&output.stdout).trim().to_string())
}

fn run_xdotool_checked_owned(
    display: &str,
    xauthority: Option<&str>,
    args: &[String],
) -> anyhow::Result<String> {
    let rendered = args.join(" ");
    let output = xdotool_command(display, xauthority)
        .args(args)
        .output()
        .with_context(|| format!("running xdotool {rendered}"))?;
    if !output.status.success() {
        anyhow::bail!(
            "xdotool {rendered} failed: {}",
            String::from_utf8_lossy(&output.stderr).trim()
        );
    }
    Ok(String::from_utf8_lossy(&output.stdout).trim().to_string())
}

fn visible_window_id_for_pid(
    display: &str,
    xauthority: Option<&str>,
    pid: u32,
) -> anyhow::Result<String> {
    let output = run_xdotool_checked(
        display,
        xauthority,
        &[
            "search",
            "--onlyvisible",
            "--pid",
            &pid.to_string(),
            "--name",
            "Yggterm",
        ],
    )?;
    output
        .lines()
        .filter(|line| !line.trim().is_empty())
        .last()
        .map(str::to_string)
        .context("no visible Yggterm X11 window found for terminal probe")
}

fn focus_terminal_viewport_via_x11(
    home: &Path,
    context: &X11TerminalProbeContext,
) -> anyhow::Result<String> {
    let window_id =
        visible_window_id_for_pid(&context.display, context.xauthority.as_deref(), context.pid)?;
    if terminal_probe_focus_ready(&context.before) {
        return Ok(window_id);
    }
    let _ = run_xdotool_checked_owned(
        &context.display,
        context.xauthority.as_deref(),
        &[
            "windowactivate".to_string(),
            "--sync".to_string(),
            window_id.clone(),
        ],
    );
    let _ = run_xdotool_checked_owned(
        &context.display,
        context.xauthority.as_deref(),
        &[
            "windowfocus".to_string(),
            "--sync".to_string(),
            window_id.clone(),
        ],
    );
    let click_points = [
        (context.x, context.y),
        (context.scroll_x, context.scroll_y),
        (context.x, context.y),
    ];
    let mut last_snapshot = context.before.clone();
    for (x, y) in click_points {
        run_xdotool_checked_owned(
            &context.display,
            context.xauthority.as_deref(),
            &[
                "mousemove".to_string(),
                "--window".to_string(),
                window_id.clone(),
                x.to_string(),
                y.to_string(),
            ],
        )?;
        run_xdotool_checked_owned(
            &context.display,
            context.xauthority.as_deref(),
            &[
                "click".to_string(),
                "--window".to_string(),
                window_id.clone(),
                "1".to_string(),
            ],
        )?;
        std::thread::sleep(Duration::from_millis(140));
        let refreshed = active_terminal_probe_context(
            home,
            &context.session_path,
            terminal_probe_snapshot_timeout_ms(4_000),
        )?;
        if terminal_probe_focus_ready(&refreshed.before) {
            return Ok(window_id);
        }
        last_snapshot = refreshed.before;
    }
    anyhow::bail!(
        "terminal viewport click did not yield helper focus for probe input: session={} snapshot={}",
        context.session_path,
        last_snapshot
    )
}

fn x11_keyboard_probe_input(
    session_path: &str,
    data: &str,
    press_enter: bool,
    press_tab: bool,
    press_ctrl_c: bool,
    press_ctrl_e: bool,
    press_ctrl_u: bool,
    timeout_ms: u64,
) -> anyhow::Result<Value> {
    let home = resolve_yggterm_home()?;
    let snapshot_timeout_ms = terminal_probe_snapshot_timeout_ms(timeout_ms);
    let before_context = active_terminal_probe_context(&home, session_path, snapshot_timeout_ms)?;
    let window_id = focus_terminal_viewport_via_x11(&home, &before_context)?;
    let mut keyboard_backend = "xdotool_window".to_string();
    let send_keys = |target_window: Option<&str>,
                     target_display: &str,
                     target_xauthority: Option<&str>|
     -> anyhow::Result<()> {
        if press_ctrl_c {
            run_xdotool_checked_owned(
                target_display,
                target_xauthority,
                &xdotool_chord_args(target_window, "ctrl", "c"),
            )?;
            std::thread::sleep(Duration::from_millis(40));
        }
        if press_ctrl_e {
            run_xdotool_checked_owned(
                target_display,
                target_xauthority,
                &xdotool_chord_args(target_window, "ctrl", "e"),
            )?;
            std::thread::sleep(Duration::from_millis(40));
        }
        if press_ctrl_u {
            run_xdotool_checked_owned(
                target_display,
                target_xauthority,
                &xdotool_chord_args(target_window, "ctrl", "u"),
            )?;
            std::thread::sleep(Duration::from_millis(40));
        }
        if !data.is_empty() {
            let type_result = run_xdotool_checked_owned(
                target_display,
                target_xauthority,
                &xdotool_type_args(target_window, data),
            );
            if type_result.is_ok() {
                std::thread::sleep(Duration::from_millis(xdotool_type_settle_delay_ms(data)));
            } else {
                let supported_keys = data
                    .chars()
                    .map(xdotool_key_for_char)
                    .collect::<Option<Vec<_>>>()
                    .with_context(|| {
                        if target_window.is_some() {
                            format!("xdotool type failed and no per-key fallback exists for {data:?}")
                        } else {
                            format!(
                                "xdotool focused-window type failed and no per-key fallback exists for {data:?}"
                            )
                        }
                    })?;
                for key in supported_keys {
                    run_xdotool_checked_owned(
                        target_display,
                        target_xauthority,
                        &xdotool_key_args(target_window, key),
                    )?;
                    std::thread::sleep(Duration::from_millis(18));
                }
            }
        }
        if press_tab {
            run_xdotool_checked_owned(
                target_display,
                target_xauthority,
                &xdotool_key_args(target_window, "Tab"),
            )?;
            std::thread::sleep(Duration::from_millis(40));
        }
        if press_enter {
            run_xdotool_checked_owned(
                target_display,
                target_xauthority,
                &xdotool_key_args(target_window, "Return"),
            )?;
        }
        Ok(())
    };
    send_keys(
        Some(&window_id),
        &before_context.display,
        before_context.xauthority.as_deref(),
    )?;
    std::thread::sleep(Duration::from_millis(if press_enter { 220 } else { 120 }));
    let mut after_context =
        active_terminal_probe_context(&home, session_path, snapshot_timeout_ms)?;
    if x11_keyboard_probe_requires_focused_retry(
        &before_context.before,
        &after_context.before,
        data,
        press_enter,
        press_tab,
        press_ctrl_c,
        press_ctrl_e,
        press_ctrl_u,
    ) {
        let retry_context =
            active_terminal_probe_context(&home, session_path, snapshot_timeout_ms)?;
        let _ = focus_terminal_viewport_via_x11(&home, &retry_context)?;
        std::thread::sleep(Duration::from_millis(180));
        send_keys(
            None,
            &retry_context.display,
            retry_context.xauthority.as_deref(),
        )?;
        keyboard_backend = if data.is_empty() {
            "xdotool_focused_window_keys".to_string()
        } else {
            "xdotool_focused_window".to_string()
        };
        std::thread::sleep(Duration::from_millis(if press_enter { 220 } else { 140 }));
        after_context = active_terminal_probe_context(&home, session_path, snapshot_timeout_ms)?;
    }
    Ok(json!({
        "accepted": true,
        "session_path": session_path,
        "host_id": null,
        "before": before_context.before,
        "after": after_context.before,
        "typed_text": data,
        "press_enter": press_enter,
        "press_tab": press_tab,
        "press_ctrl_c": press_ctrl_c,
        "press_ctrl_e": press_ctrl_e,
        "press_ctrl_u": press_ctrl_u,
        "mode": "keyboard",
        "used_core_trigger": false,
        "used_term_input": false,
        "keyboard_backend": keyboard_backend,
        "window_id": window_id,
        "click_point": {
            "x": before_context.x,
            "y": before_context.y,
        },
    }))
}

fn x11_scroll_probe_input(
    session_path: &str,
    lines: i32,
    timeout_ms: u64,
) -> anyhow::Result<Value> {
    let home = resolve_yggterm_home()?;
    let snapshot_timeout_ms = terminal_probe_snapshot_timeout_ms(timeout_ms);
    let before_context = active_terminal_probe_context(&home, session_path, snapshot_timeout_ms)?;
    let window_id = focus_terminal_viewport_via_x11(&home, &before_context)?;
    if lines != 0 {
        let button = if lines > 0 { "5" } else { "4" };
        let repeat = lines.unsigned_abs().max(1).to_string();
        run_xdotool_checked_owned(
            &before_context.display,
            before_context.xauthority.as_deref(),
            &[
                "mousemove".to_string(),
                "--window".to_string(),
                window_id.clone(),
                before_context.scroll_x.to_string(),
                before_context.scroll_y.to_string(),
            ],
        )?;
        run_xdotool_checked_owned(
            &before_context.display,
            before_context.xauthority.as_deref(),
            &[
                "click".to_string(),
                "--window".to_string(),
                window_id.clone(),
                "1".to_string(),
            ],
        )?;
        run_xdotool_checked_owned(
            &before_context.display,
            before_context.xauthority.as_deref(),
            &[
                "click".to_string(),
                "--window".to_string(),
                window_id.clone(),
                "--repeat".to_string(),
                repeat,
                "--delay".to_string(),
                "25".to_string(),
                button.to_string(),
            ],
        )?;
        std::thread::sleep(Duration::from_millis(120));
    }
    let after_context = active_terminal_probe_context(&home, session_path, snapshot_timeout_ms)?;
    let movement_expected = terminal_scroll_probe_snapshot_can_move(&before_context.before, lines);
    let scroll_probe_moved =
        terminal_scroll_probe_snapshot_moved(&before_context.before, &after_context.before);
    Ok(json!({
        "accepted": true,
        "session_path": session_path,
        "before": before_context.before,
        "after": after_context.before,
        "lines": lines,
        "movement_expected": movement_expected,
        "scroll_probe_moved": scroll_probe_moved,
        "mode": "keyboard",
        "keyboard_backend": "xdotool",
        "window_id": window_id,
        "click_point": {
            "x": before_context.scroll_x,
            "y": before_context.scroll_y,
        },
    }))
}

fn app_control_skip_x11_synthetic_input() -> bool {
    if !std::env::var("YGGTERM_APP_CONTROL_ENABLE_DESKTOP_SYNTHETIC_INPUT")
        .ok()
        .map(|value| {
            matches!(
                value.trim().to_ascii_lowercase().as_str(),
                "1" | "true" | "yes" | "on"
            )
        })
        .unwrap_or(false)
    {
        return true;
    }
    std::env::var("YGGTERM_APP_CONTROL_SKIP_X11_SYNTHETIC_INPUT")
        .ok()
        .map(|value| {
            matches!(
                value.trim().to_ascii_lowercase().as_str(),
                "1" | "true" | "yes" | "on"
            )
        })
        .unwrap_or(false)
}

pub fn run_app_control_probe_terminal_viewport_input(
    session_path: &str,
    data: &str,
    mode: ProbeTerminalViewportInputMode,
    per_char: bool,
    press_enter: bool,
    press_tab: bool,
    press_ctrl_c: bool,
    press_ctrl_e: bool,
    press_ctrl_u: bool,
    timeout_ms: u64,
) -> anyhow::Result<()> {
    if !per_char
        && !app_control_skip_x11_synthetic_input()
        && matches!(
            mode,
            ProbeTerminalViewportInputMode::Auto | ProbeTerminalViewportInputMode::Keyboard
        )
    {
        if let Ok(response) = x11_keyboard_probe_input(
            session_path,
            data,
            press_enter,
            press_tab,
            press_ctrl_c,
            press_ctrl_e,
            press_ctrl_u,
            timeout_ms,
        ) {
            write_stdout_payload(&serde_json::to_string_pretty(&response)?)?;
            return Ok(());
        }
    }
    let home = resolve_yggterm_home()?;
    let response = request_app_control(
        &home,
        AppControlCommand::ProbeTerminalViewportInput {
            session_path: session_path.to_string(),
            data: data.to_string(),
            mode,
            per_char,
            press_enter,
            press_tab,
            press_ctrl_c,
            press_ctrl_e,
            press_ctrl_u,
        },
        timeout_ms,
    )?;
    write_stdout_payload(&serde_json::to_string_pretty(&response)?)?;
    Ok(())
}

