pub fn run_remote_generation_context(path: &str) -> anyhow::Result<()> {
    let context = generation_context_from_messages(
        &read_codex_transcript_messages(std::path::Path::new(path))
            .with_context(|| format!("reading remote transcript {}", path))?,
    );
    write_stdout_line(&context)?;
    Ok(())
}

fn write_stdout_line(line: &str) -> anyhow::Result<()> {
    let mut stdout = std::io::stdout().lock();
    match writeln!(stdout, "{line}") {
        Ok(()) => Ok(()),
        Err(error) if error.kind() == std::io::ErrorKind::BrokenPipe => Ok(()),
        Err(error) => Err(error.into()),
    }
}

fn write_stdout_line_strict(line: &str) -> anyhow::Result<()> {
    let mut stdout = std::io::stdout().lock();
    writeln!(stdout, "{line}")?;
    Ok(())
}

pub fn run_remote_upsert_generated_copy(payload_json: &str) -> anyhow::Result<()> {
    let payload: RemoteGeneratedCopyPayload =
        serde_json::from_str(payload_json).context("parsing remote generated copy payload")?;
    let home = resolve_yggterm_home()?;
    let db_path = home.join("session-titles.db");
    if let Some(parent) = db_path.parent() {
        fs::create_dir_all(parent)
            .with_context(|| format!("creating title db dir {}", parent.display()))?;
    }
    let conn = Connection::open(&db_path)
        .with_context(|| format!("opening session title db {}", db_path.display()))?;
    conn.execute_batch(
        "CREATE TABLE IF NOT EXISTS session_titles (
            session_id TEXT PRIMARY KEY,
            title TEXT NOT NULL,
            cwd TEXT,
            source TEXT,
            model TEXT,
            updated_at TEXT NOT NULL
        );
        CREATE TABLE IF NOT EXISTS session_precis (
            session_id TEXT PRIMARY KEY,
            precis TEXT NOT NULL,
            cwd TEXT,
            source TEXT,
            model TEXT,
            updated_at TEXT NOT NULL
        );
        CREATE TABLE IF NOT EXISTS session_summaries (
            session_id TEXT PRIMARY KEY,
            summary TEXT NOT NULL,
            cwd TEXT,
            source TEXT,
            model TEXT,
            updated_at TEXT NOT NULL
        );
        CREATE TABLE IF NOT EXISTS session_summary_timeline (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            session_id TEXT NOT NULL,
            summary TEXT NOT NULL,
            cwd TEXT,
            source TEXT,
            model TEXT,
            created_at TEXT NOT NULL
        );
        CREATE INDEX IF NOT EXISTS idx_session_summary_timeline_session_created
            ON session_summary_timeline(session_id, created_at DESC);",
    )?;
    if let Some(title) = payload
        .title
        .as_deref()
        .filter(|value| !value.trim().is_empty())
    {
        let existing_title = conn
            .query_row(
                "SELECT title, source FROM session_titles WHERE session_id = ?1",
                params![payload.session_id],
                |row| Ok((row.get::<_, String>(0)?, row.get::<_, Option<String>>(1)?)),
            )
            .optional()?;
        let preserve_existing_title = should_preserve_existing_remote_title(
            title,
            &payload.source,
            existing_title.as_ref().map(|(title, _)| title.as_str()),
            existing_title
                .as_ref()
                .and_then(|(_, source)| source.as_deref()),
        );
        if !preserve_existing_title {
            conn.execute(
                "INSERT INTO session_titles (session_id, title, cwd, source, model, updated_at)
                 VALUES (?1, ?2, ?3, ?4, ?5, ?6)
                 ON CONFLICT(session_id) DO UPDATE SET
                   title = excluded.title,
                   cwd = excluded.cwd,
                   source = excluded.source,
                   model = excluded.model,
                   updated_at = excluded.updated_at",
                params![
                    payload.session_id,
                    title,
                    payload.cwd,
                    payload.source,
                    payload.model,
                    payload.updated_at,
                ],
            )?;
        }
    }
    if let Some(precis) = payload
        .precis
        .as_deref()
        .filter(|value| !value.trim().is_empty())
    {
        conn.execute(
            "INSERT INTO session_precis (session_id, precis, cwd, source, model, updated_at)
             VALUES (?1, ?2, ?3, ?4, ?5, ?6)
             ON CONFLICT(session_id) DO UPDATE SET
               precis = excluded.precis,
               cwd = excluded.cwd,
               source = excluded.source,
               model = excluded.model,
               updated_at = excluded.updated_at",
            params![
                payload.session_id,
                precis,
                payload.cwd,
                payload.source,
                payload.model,
                payload.updated_at,
            ],
        )?;
    }
    if let Some(summary) = payload
        .summary
        .as_deref()
        .filter(|value| !value.trim().is_empty())
    {
        if payload.reset_summary_history {
            conn.execute(
                "DELETE FROM session_summary_timeline WHERE session_id = ?1",
                params![payload.session_id],
            )?;
        }
        conn.execute(
            "INSERT INTO session_summaries (session_id, summary, cwd, source, model, updated_at)
             VALUES (?1, ?2, ?3, ?4, ?5, ?6)
             ON CONFLICT(session_id) DO UPDATE SET
               summary = excluded.summary,
               cwd = excluded.cwd,
               source = excluded.source,
               model = excluded.model,
               updated_at = excluded.updated_at",
            params![
                payload.session_id,
                summary,
                payload.cwd,
                payload.source,
                payload.model,
                payload.updated_at,
            ],
        )?;
        let latest_timeline_summary = conn
            .query_row(
                "SELECT summary
                 FROM session_summary_timeline
                 WHERE session_id = ?1
                 ORDER BY created_at DESC, id DESC
                 LIMIT 1",
                params![payload.session_id],
                |row| row.get::<_, String>(0),
            )
            .optional()?;
        if latest_timeline_summary.as_deref().map(str::trim) != Some(summary.trim()) {
            conn.execute(
                "INSERT INTO session_summary_timeline
                    (session_id, summary, cwd, source, model, created_at)
                 VALUES (?1, ?2, ?3, ?4, ?5, ?6)",
                params![
                    payload.session_id,
                    summary,
                    payload.cwd,
                    payload.source,
                    payload.model,
                    payload.updated_at,
                ],
            )?;
        }
    }
    Ok(())
}

pub fn persist_remote_generated_copy(
    machine: &RemoteMachineSnapshot,
    session_id: &str,
    cwd: &str,
    title: Option<&str>,
    precis: Option<&str>,
    summary: Option<&str>,
    model: &str,
) -> anyhow::Result<()> {
    persist_remote_generated_copy_with_options(
        machine, session_id, cwd, title, precis, summary, model, false,
    )
}

pub fn persist_remote_generated_copy_with_options(
    machine: &RemoteMachineSnapshot,
    session_id: &str,
    cwd: &str,
    title: Option<&str>,
    precis: Option<&str>,
    summary: Option<&str>,
    model: &str,
    reset_summary_history: bool,
) -> anyhow::Result<()> {
    let updated_at =
        time::OffsetDateTime::now_utc().format(&time::format_description::well_known::Rfc3339)?;
    let payload = RemoteGeneratedCopyPayload {
        session_id: session_id.to_string(),
        cwd: cwd.to_string(),
        title: title.map(ToOwned::to_owned),
        precis: precis.map(ToOwned::to_owned),
        summary: summary.map(ToOwned::to_owned),
        model: model.to_string(),
        source: "interface-llm".to_string(),
        updated_at,
        reset_summary_history,
    };
    let payload_json = serde_json::to_string(&payload)?;
    match run_remote_yggterm_command(
        &machine.ssh_target,
        machine.prefix.as_deref(),
        &["server", "remote", "upsert-generated-copy", &payload_json],
        None,
    ) {
        Ok(_) => {}
        Err(error) if !should_fallback_to_python(&error) => return Err(error),
        Err(_) => {
            let args = vec![payload_json];
            let _ = run_remote_python(
                &machine.ssh_target,
                machine.prefix.as_deref(),
                REMOTE_UPSERT_GENERATED_COPY_SCRIPT,
                &args,
            )?;
        }
    }
    if let Err(error) = update_remote_generated_copy_in_mirror(
        &machine.machine_key,
        session_id,
        title,
        precis,
        summary,
    ) {
        warn!(machine_key=%machine.machine_key, session_id, error=%error, "failed to update local remote metadata mirror");
    }
    Ok(())
}

pub fn terminate_remote_codex_session(
    machine: &RemoteMachineSnapshot,
    session_id: &str,
) -> anyhow::Result<()> {
    // Daemon-native termination is the SSOT: the remote host daemon owns the
    // session. No external multiplexer (tmux/screen) fallback anywhere.
    run_remote_yggterm_command(
        &machine.ssh_target,
        machine.prefix.as_deref(),
        &["server", "remote", "terminate-codex", session_id],
        None,
    )
    .map(|_| ())
}

pub fn request_remote_codex_session_shutdown(
    machine: &RemoteMachineSnapshot,
    session_id: &str,
    force_after: Duration,
) -> anyhow::Result<()> {
    request_remote_codex_session_quit(machine, session_id)?;
    let machine = machine.clone();
    let session_id = session_id.to_string();
    std::thread::spawn(move || {
        std::thread::sleep(force_after);
        let _ = terminate_remote_codex_session(&machine, &session_id);
    });
    Ok(())
}

fn request_remote_codex_session_quit(
    machine: &RemoteMachineSnapshot,
    session_id: &str,
) -> anyhow::Result<()> {
    // Graceful quit now goes through the daemon-native terminate path (idempotent
    // with the scheduled force-terminate that follows). No tmux/screen anywhere.
    terminate_remote_codex_session(machine, session_id)
}

