    #[cfg(unix)]
    #[test]
    fn remote_command_wait_times_out_hung_child() {
        let child = Command::new("sh")
            .arg("-c")
            .arg("exec sleep 5")
            .stdin(Stdio::null())
            .stdout(Stdio::piped())
            .stderr(Stdio::piped())
            .spawn()
            .expect("spawn test child");
        let started = Instant::now();
        let error = wait_remote_command_with_timeout(child, 50, "timeout-test")
            .expect_err("hung child should time out");
        assert!(started.elapsed() < Duration::from_secs(2));
        assert!(error.to_string().contains("timed out"));
    }

    #[cfg(unix)]
    #[test]
    fn remote_command_wait_drains_large_stdout_while_child_runs() {
        let child = Command::new("sh")
            .arg("-c")
            .arg("head -c 262144 /dev/zero")
            .stdin(Stdio::null())
            .stdout(Stdio::piped())
            .stderr(Stdio::piped())
            .spawn()
            .expect("spawn test child");
        let output = wait_remote_command_with_timeout(child, 2_000, "large-output-test")
            .expect("large stdout should not deadlock the remote command waiter");
        assert!(output.status.success());
        assert_eq!(output.stdout.len(), 262144);
        assert!(output.stderr.is_empty());
    }

