    // XTERM-BUG: squish-and-bottom-paint-on-reresume — the PTY grid is recorded in
    // the session_pty_grids map so a re-resume restores the real grid instead of
    // DEFAULT 120x36 (the background-session squish). In-memory roundtrip + zero-guard.
    #[test]
    fn session_pty_grid_roundtrips_in_memory() {
        let mut server = test_server();
        let path = server.start_local_session(SessionKind::Codex, Some("/home/pi"), Some("codex"));
        assert_eq!(server.session_pty_grid(&path), None);
        server.record_session_pty_grid(&path, 159, 63);
        assert_eq!(server.session_pty_grid(&path), Some((159, 63)));
        // Zero dims are ignored (no clobber of a good grid).
        server.record_session_pty_grid(&path, 0, 0);
        assert_eq!(server.session_pty_grid(&path), Some((159, 63)));
    }

    // The synchronous-flush logic in the TerminalResize handler + record-on-create
    // flushes to disk only when the grid actually CHANGED. Guard that contract so a
    // refactor can't turn every redundant resize into a write storm (or, worse, stop
    // flushing real changes → the squish regresses). See campaign D1.
    #[test]
    fn record_session_pty_grid_reports_change_for_flush_gating() {
        let mut server = test_server();
        let path = server.start_local_session(SessionKind::Codex, Some("/home/pi"), Some("codex"));
        assert!(
            server.record_session_pty_grid(&path, 159, 63),
            "first record of a grid is a change → must flush"
        );
        assert!(
            !server.record_session_pty_grid(&path, 159, 63),
            "re-recording the SAME grid is not a change → must NOT flush (no write storm)"
        );
        assert!(
            server.record_session_pty_grid(&path, 167, 63),
            "a different grid is a change → must flush"
        );
        // Zero dims never count as a change.
        assert!(!server.record_session_pty_grid(&path, 0, 0));
        assert_eq!(server.session_pty_grid(&path), Some((167, 63)));
    }

    // Bug 9 (dual-store collision = the ~3s blink): a kind=document stored entry whose
    // path is a runtime URI is a bogus twin of a live codex of the same UUID. It must
    // be filtered at BOTH persist and restore so the GUI can't oscillate Rendered
    // (document) <-> Terminal (codex). See finding-dual-store-codex-mount-failure.
    #[test]
    fn stored_document_runtime_uri_twin_is_filtered_at_persist_and_restore() {
        // The predicate: a document MUST NOT own a runtime URI; real docs are virtual.
        assert!(super::stored_document_owns_runtime_uri(
            SessionKind::Document,
            "codex-runtime://019e9c28-e46d-7480-9f27-4e5676df61b1"
        ));
        assert!(super::stored_document_owns_runtime_uri(
            SessionKind::Document,
            "local://019e9c28-e46d-7480-9f27-4e5676df61b1"
        ));
        // A real document (virtual path) is NOT filtered.
        assert!(!super::stored_document_owns_runtime_uri(
            SessionKind::Document,
            "/documents/notes/foo"
        ));
        // A codex session keyed by a runtime URI is NOT a document — never filtered.
        assert!(!super::stored_document_owns_runtime_uri(
            SessionKind::Codex,
            "codex-runtime://019e9c28-e46d-7480-9f27-4e5676df61b1"
        ));

        // End-to-end: a persisted state carrying the bogus twin must not survive a
        // restore (the daemon-process restart that re-reads disk drops it).
        let bogus = PersistedDaemonState {
            active_session_path: None,
            active_view_mode: WorkspaceViewMode::Rendered,
            ssh_targets: Vec::new(),
            remote_machines: Vec::new(),
            stored_sessions: vec![PersistedStoredSession {
                path: "codex-runtime://019e9c28-e46d-7480-9f27-4e5676df61b1".to_string(),
                kind: SessionKind::Document,
                session_id: Some("019e9c28-e46d-7480-9f27-4e5676df61b1".to_string()),
                cwd: None,
                title_hint: Some("019e9c28-e46d-7480-9f27-4e5676df61b1".to_string()),
            }],
            live_sessions: Vec::new(),
            session_pty_grids: Vec::new(),
        };
        let mut server = test_server();
        server.restore_persisted_state_with_launch_policy(bogus, None, false);
        assert!(
            !server
                .sessions
                .contains_key("codex-runtime://019e9c28-e46d-7480-9f27-4e5676df61b1"),
            "the bogus document twin must be dropped on restore, not collide with the codex"
        );
    }

    // XTERM-BUG: squish — the v2.8.31 in-memory-only fix did NOT survive a daemon
    // PROCESS restart (recGrid=None after the 2.8.32 swap), which IS the squish's
    // primary scenario. This test simulates that restart: persist -> serialize ->
    // deserialize -> restore into a FRESH server -> the grid must survive so the
    // re-resumed session comes back at its real grid, not DEFAULT 120x36.
    #[test]
    fn session_pty_grid_survives_daemon_process_restart() {
        let mut server = test_server();
        // The grid map persists for any session still in `self.sessions`, regardless
        // of source or keep-alive — local-live sessions (where the squish was first
        // measured) are absent from live_sessions, so the map is what carries them.
        let path = server.start_local_session(SessionKind::Codex, Some("/home/pi"), Some("codex"));
        server.record_session_pty_grid(&path, 159, 63);

        // Serialize the persisted state exactly as the daemon writes it on
        // update-restart, then deserialize as the successor daemon reads it.
        let persisted = server.persisted_state_for_update_restart();
        assert!(
            persisted
                .session_pty_grids
                .iter()
                .any(|g| g.cols == 159 && g.rows == 63),
            "grid must be present in the persisted state"
        );
        let wire = serde_json::to_string(&persisted).expect("serialize");
        let restored: PersistedDaemonState = serde_json::from_str(&wire).expect("deserialize");

        // Fresh successor daemon: drop all in-memory state, restore from disk.
        let mut successor = test_server();
        successor.restore_persisted_state_with_launch_policy(restored, None, false);
        assert_eq!(
            successor.session_pty_grid(&path),
            Some((159, 63)),
            "grid must survive a daemon PROCESS restart so re-resume isn't squished"
        );
    }

    #[test]
    fn ensure_shell_runtime_session_is_resumable_and_daemon_owned() {
        // The tmux replacement: `server attach <id>` maps to a daemon-owned,
        // resumable shell session. The same id must resolve to the SAME session
        // key (so re-attach reconnects the persistent PTY), the kind must be a
        // plain Shell, and the launch command must be a bare login shell (the
        // daemon spawns it in the session cwd — no tmux/PROMPT_COMMAND dance).
        let tree = SessionNode {
            kind: SessionNodeKind::Group,
            name: "root".to_string(),
            title: None,
            document_kind: None,
            group_kind: None,
            path: PathBuf::from("/"),
            children: Vec::new(),
            session_id: None,
            cwd: None,
            ..Default::default()
        };
        let mut server = YggtermServer::new(
            &tree,
            false,
            GhosttyHostSupport::shadow("test".to_string(), false, false),
            UiTheme::ZedLight,
        );
        let id = "testshell-resume-001";
        let key1 = server
            .ensure_shell_runtime_session(id, Some("/tmp"))
            .expect("first ensure");
        let key2 = server
            .ensure_shell_runtime_session(id, Some("/tmp"))
            .expect("second ensure");
        assert_eq!(key1, key2, "same id must resolve to the same resumable key");

        let session = server.sessions.get(&key1).expect("session present");
        assert_eq!(session.kind, SessionKind::Shell);
        assert_eq!(session.id, id);
        assert!(
            session.launch_command.contains("-i"),
            "expected an interactive login shell launch command, got {:?}",
            session.launch_command
        );
        assert!(
            !session.launch_command.contains("tmux")
                && !session.launch_command.contains("screen"),
            "shell launch command must not invoke any external multiplexer: {:?}",
            session.launch_command
        );
    }

    #[test]
