    #[test]
    fn terminal_scroll_probe_requires_actual_movement_when_scrollback_can_move() {
        let before = json!({
            "viewport_y": 124,
            "base_y": 124,
            "viewport_scroll_top": 2232.0,
            "rows": 50,
            "last_raw_payload_line_count": 197,
            "text_head": "top",
            "text_tail": "bottom",
            "wheel_event_count": 0,
            "scroll_event_count": 0,
        });
        let unchanged = json!({
            "viewport_y": 124,
            "base_y": 124,
            "viewport_scroll_top": 2232.0,
            "rows": 50,
            "last_raw_payload_line_count": 197,
            "text_head": "top",
            "text_tail": "bottom",
            "wheel_event_count": 0,
            "scroll_event_count": 0,
        });
        let moved = json!({
            "viewport_y": 104,
            "base_y": 124,
            "viewport_scroll_top": 1872.0,
            "rows": 50,
            "last_raw_payload_line_count": 197,
            "text_head": "older",
            "text_tail": "bottom",
            "wheel_event_count": 1,
            "scroll_event_count": 1,
        });
        let event_only = json!({
            "viewport_y": 124,
            "base_y": 124,
            "viewport_scroll_top": 2232.0,
            "rows": 50,
            "last_raw_payload_line_count": 197,
            "text_head": "top changed by live output",
            "text_tail": "bottom changed by live output",
            "wheel_event_count": 1,
            "scroll_event_count": 1,
        });
        let raw_lines_only = json!({
            "viewport_y": 0,
            "base_y": 0,
            "viewport_scroll_top": 0.0,
            "rows": 50,
            "last_raw_payload_line_count": 197,
            "scrollback_expected": true,
            "text_head": "top",
            "text_tail": "bottom",
            "wheel_event_count": 0,
            "scroll_event_count": 0,
        });

        assert!(super::terminal_scroll_probe_snapshot_can_move(&before, -20));
        assert!(!super::terminal_scroll_probe_snapshot_can_move(&before, 20));
        assert!(!super::terminal_scroll_probe_snapshot_can_move(
            &raw_lines_only,
            -20
        ));
        assert!(!super::terminal_scroll_probe_snapshot_moved(
            &before, &unchanged
        ));
        assert!(!super::terminal_scroll_probe_snapshot_moved(
            &before,
            &event_only
        ));
        assert!(super::terminal_scroll_probe_snapshot_moved(&before, &moved));
    }

    #[test]
    fn saved_session_does_not_attach_when_visible_screen_is_invalid() -> Result<()> {
        let home = std::env::temp_dir().join(format!(
            "yggterm-remote-attach-{}-{}",
            std::process::id(),
            time::OffsetDateTime::now_utc().unix_timestamp_nanos()
        ));
        let sessions_dir = home.join("sessions").join("2026").join("04");
        fs::create_dir_all(&sessions_dir)?;
        fs::write(
            sessions_dir.join("rollout-test.jsonl"),
            concat!(
                "{\"id\":\"abc123\",\"cwd\":\"/home/pi\"}\n",
                "{\"timestamp\":\"2026-03-20T10:00:00Z\",\"type\":\"response_item\",\"payload\":{\"type\":\"message\",\"role\":\"user\",\"content\":[{\"type\":\"input_text\",\"text\":\"make a passwordless user pi\"}]}}\n",
                "{\"timestamp\":\"2026-03-20T10:00:01Z\",\"type\":\"response_item\",\"payload\":{\"type\":\"message\",\"role\":\"assistant\",\"content\":[{\"type\":\"output_text\",\"text\":\"I will create the pi account without a password.\"}]}}\n"
            ),
        )?;
        let _codex_home_guard = CODEX_HOME_TEST_LOCK.lock().expect("CODEX_HOME test lock");
        let previous_codex_home = std::env::var_os("CODEX_HOME");
        unsafe {
            std::env::set_var("CODEX_HOME", &home);
        }

        let visible = b">_ OpenAI Codex (v0.118.0)\nmodel: gpt-5.4 high /model to change\ndirectory: ~\n\nConversation interrupted - tell the model what to do differently. Something went wrong? Hit /feedback to report the issue.\n";
        let full = b">_ OpenAI Codex (v0.118.0)\nmodel: gpt-5.4 high /model to change\ndirectory: ~\n\n: make a passwordless user pi\n\" I will create the pi account without a password.\n\nConversation interrupted - tell the model what to do differently. Something went wrong? Hit /feedback to report the issue.\n";

        let attachable = remote_saved_session_screen_is_attachable("abc123", true, visible, full);

        if let Some(previous_codex_home) = previous_codex_home {
            unsafe {
                std::env::set_var("CODEX_HOME", previous_codex_home);
            }
        } else {
            unsafe {
                std::env::remove_var("CODEX_HOME");
            }
        }
        let _ = fs::remove_dir_all(home);

        assert!(!attachable);
        Ok(())
    }

