    #[test]
    fn persisted_state_includes_recoverable_local_live_sessions_and_skips_documents() {
        let tree = SessionNode {
            kind: SessionNodeKind::Group,
            name: "sessions".to_string(),
            title: None,
            document_kind: None,
            group_kind: None,
            path: PathBuf::from("/"),
            children: Vec::new(),
            session_id: None,
            cwd: None,
            ..Default::default()
        };
        let mut server = YggtermServer::new(
            &tree,
            false,
            GhosttyHostSupport::shadow("test".to_string(), false, false),
            UiTheme::ZedLight,
        );
        let remote_path = remote_scanned_session_path("dev", "abc123");
        server.remote_machines.push(RemoteMachineSnapshot {
            machine_key: "dev".to_string(),
            label: "dev".to_string(),
            ssh_target: "dev".to_string(),
            prefix: None,
            remote_binary_expr: Some("$HOME/.yggterm/bin/yggterm".to_string()),
            remote_deploy_state: RemoteDeployState::Ready,
            health: RemoteMachineHealth::Healthy,
            sessions: vec![RemoteScannedSession {
                session_path: remote_path.clone(),
                session_id: "abc123".to_string(),
                cwd: "/home/pi/gh/yggterm".to_string(),
                started_at: "2026-03-28T12:00:00Z".to_string(),
                modified_epoch: 1,
                event_count: 8,
                user_message_count: 4,
                assistant_message_count: 4,
                title_hint: "Restore Live Remote".to_string(),
                recent_context: "USER: restore".to_string(),
                cached_precis: Some("precis".to_string()),
                cached_summary: Some("summary".to_string()),
                live_runtime: true,
                storage_path: "/home/pi/.codex/sessions/abc123.jsonl".to_string(),
            }],
        });
        server.restore_live_session(PersistedLiveSession {
            key: remote_path.clone(),
            id: "abc123".to_string(),
            title: "Restore Live Remote".to_string(),
            kind: SessionKind::SshShell,
            keep_alive: true,
            ssh_target: "dev".to_string(),
            prefix: None,
            cwd: Some("/home/pi/gh/yggterm".to_string()),
            remote_launch_action: None,
            storage_path: None,
            restore_reason: None,
        });
        let local_shell = server.start_local_session(
            SessionKind::Shell,
            Some("/home/pi/gh/yggterm"),
            Some("Smoke Local Shell"),
        );
        let local_codex = server.start_local_session(
            SessionKind::Codex,
            Some("/home/pi/gh/codex-litellm"),
            Some("Remote Codex 019d1518"),
        );
        server.start_local_session(
            SessionKind::Document,
            Some("/home/pi"),
            Some("local::ddf8f1ee-8e64-4201-ab3a-2b07424f9b77"),
        );
        server
            .set_live_session_keep_alive(&remote_path, true)
            .expect("keep remote live session");
        server
            .set_live_session_keep_alive(&local_shell, true)
            .expect("keep local shell");
        server
            .set_live_session_keep_alive(&local_codex, true)
            .expect("keep local codex");

        let persisted = server.persisted_state();
        assert_eq!(persisted.live_sessions.len(), 3);
        assert!(
            persisted
                .live_sessions
                .iter()
                .any(|live| live.key == remote_path && live.ssh_target == "dev")
        );
        assert!(
            persisted
                .live_sessions
                .iter()
                .any(|live| { live.kind == SessionKind::Shell && live.ssh_target == "localhost" })
        );
        assert!(
            persisted
                .live_sessions
                .iter()
                .any(|live| { live.kind == SessionKind::Codex && live.ssh_target == "localhost" })
        );
        assert!(
            !persisted
                .live_sessions
                .iter()
                .any(|live| live.kind == SessionKind::Document)
        );
    }

    #[test]
    fn persisted_state_only_keeps_explicitly_kept_live_sessions() {
        let tree = SessionNode {
            kind: SessionNodeKind::Group,
            name: "sessions".to_string(),
            title: None,
            document_kind: None,
            group_kind: None,
            path: PathBuf::from("/"),
            children: Vec::new(),
            session_id: None,
            cwd: None,
            ..Default::default()
        };
        let mut server = YggtermServer::new(
            &tree,
            false,
            GhosttyHostSupport::shadow("test".to_string(), false, false),
            UiTheme::ZedLight,
        );
        let local_shell = server.start_local_session(
            SessionKind::Shell,
            Some("/home/pi/gh/yggterm"),
            Some("Ephemeral Local Shell"),
        );

        let persisted = server.persisted_state();
        assert!(persisted.live_sessions.is_empty());

        assert!(
            server
                .set_live_session_keep_alive(&local_shell, true)
                .expect("mark shell keep-alive")
        );
        let persisted = server.persisted_state();
        assert_eq!(persisted.live_sessions.len(), 1);
        assert_eq!(persisted.live_sessions[0].key, local_shell);
        assert!(persisted.live_sessions[0].keep_alive);

        assert!(
            server
                .set_live_session_keep_alive(&local_shell, false)
                .expect("clear shell keep-alive")
        );
        let persisted = server.persisted_state();
        assert!(persisted.live_sessions.is_empty());
    }

