    #[test]
    fn local_live_codex_sessions_survive_daemon_restart_via_persistence() {
        // Logical-blunder fix (2026-06-11): local live sessions were silently
        // dropped from PersistedDaemonState (the mapper required ssh_target),
        // so their row/title/Storage identity lived only in daemon memory and
        // died at every swap — even though the codex transcript is durable on
        // disk. Persist → restore into a FRESH server must keep the row.
        use crate::{is_loopback_ssh_target, persisted_live_session_is_recoverable};
        let tree = SessionNode {
            kind: SessionNodeKind::Group,
            name: "sessions".to_string(),
            path: PathBuf::from("/"),
            ..Default::default()
        };
        let mut server = YggtermServer::new(
            &tree,
            false,
            GhosttyHostSupport::shadow("test".to_string(), false, false),
            UiTheme::ZedLight,
        );
        let key = server.start_local_session(
            SessionKind::Codex,
            Some("/home/pi"),
            Some("Proxy Smoke Test Run"),
        );
        if let Some(session) = server.sessions.get_mut(&key) {
            upsert_session_metadata(
                &mut session.metadata,
                "Storage",
                "/home/pi/.codex/sessions/2026/06/06/rollout-test.jsonl".to_string(),
            );
        }

        // Update-restart persistence (protect_all_live) must include the
        // local session even without keep-alive.
        let persisted = server.persisted_state_with_update_protection(true, None);
        let live = persisted
            .live_sessions
            .iter()
            .find(|live| live.key == key)
            .expect("local live codex session must be persisted across a daemon swap");
        assert!(is_loopback_ssh_target(&live.ssh_target));
        assert_eq!(live.title, "Proxy Smoke Test Run");
        assert_eq!(
            live.storage_path.as_deref(),
            Some("/home/pi/.codex/sessions/2026/06/06/rollout-test.jsonl")
        );
        assert!(persisted_live_session_is_recoverable(live));
        let live = live.clone();

        // LIVE-PATH VARIANTS (2.8.79 incident: this roundtrip passed while
        // the live swap still dropped the rows — pin the gate offline):
        // (a) update-restart passes Some(protected_runtime_keys); a session
        //     whose key is in the set must persist…
        let protected: HashSet<String> = [key.clone()].into_iter().collect();
        let with_protected = server.persisted_state_with_update_protection(true, Some(&protected));
        assert!(
            with_protected.live_sessions.iter().any(|l| l.key == key),
            "local session with its key in protected_runtime_keys must persist"
        );
        // …and one outside the set is dropped — the documented gate.
        let other: HashSet<String> = ["local://someone-else".to_string()].into_iter().collect();
        let without = server.persisted_state_with_update_protection(true, Some(&other));
        assert!(
            !without.live_sessions.iter().any(|l| l.key == key),
            "session outside protected_runtime_keys is dropped (gate documented)"
        );
        // Bug-9 key duality (live drop-telemetry catch): the PTY may be keyed
        // codex-runtime://<uuid> in the terminals manager while the row is
        // local://<uuid> — the codex-runtime alias must match the gate.
        let id = server
            .sessions
            .get(&key)
            .map(|session| session.id.clone())
            .expect("session id");
        let alias_protected: HashSet<String> =
            [remote_runtime_codex_session_key(&id)].into_iter().collect();
        let with_alias =
            server.persisted_state_with_update_protection(true, Some(&alias_protected));
        assert!(
            with_alias.live_sessions.iter().any(|l| l.key == key),
            "codex-runtime:// alias in protected_runtime_keys must protect the local:// row"
        );
        // (b) a recovery-created session may carry source=Stored; it must
        //     still be recoverable while holding a live local runtime key.
        if let Some(session) = server.sessions.get_mut(&key) {
            session.source = SessionSource::Stored;
        }
        let stored_source = server.persisted_state_with_update_protection(true, None);
        assert!(
            stored_source.live_sessions.iter().any(|l| l.key == key),
            "a source=Stored session holding a live local runtime key must still persist"
        );
        if let Some(session) = server.sessions.get_mut(&key) {
            session.source = SessionSource::LiveLocal;
        }

        // Restore into a FRESH server (the daemon-process restart) keeps the row.
        let mut fresh = YggtermServer::new(
            &tree,
            false,
            GhosttyHostSupport::shadow("test".to_string(), false, false),
            UiTheme::ZedLight,
        );
        fresh.restore_live_session(live.clone());
        let restored_key = fresh
            .live_session_order
            .iter()
            .find(|existing| existing.contains(&live.id))
            .cloned()
            .expect("restored local codex session must reappear in live order");
        let restored = fresh.sessions.get(&restored_key).expect("restored session");
        assert_eq!(restored.kind, SessionKind::Codex);
        assert_eq!(restored.title, "Proxy Smoke Test Run");
    }

    #[test]
    fn place_live_session_after_inserts_below_anchor_and_fails_open() {
        // User bug (2026-06-10 #7): context-menu "Open new terminal/CC/codex
        // here" always landed at the TOP of Live Sessions; it must land
        // directly below the right-clicked row.
        let tree = SessionNode {
            kind: SessionNodeKind::Group,
            name: "sessions".to_string(),
            title: None,
            document_kind: None,
            group_kind: None,
            path: PathBuf::from("/"),
            children: Vec::new(),
            session_id: None,
            cwd: None,
            ..Default::default()
        };
        let mut server = YggtermServer::new(
            &tree,
            false,
            GhosttyHostSupport::shadow("test".to_string(), false, false),
            UiTheme::ZedLight,
        );
        let a = server.start_local_session(SessionKind::Shell, Some("/home/pi"), Some("a"));
        let b = server.start_local_session(SessionKind::Shell, Some("/home/pi"), Some("b"));
        let new = server.start_local_session(SessionKind::Shell, Some("/home/pi"), Some("new"));
        assert_eq!(server.live_session_order, vec![new.clone(), b.clone(), a.clone()]);

        // Anchor on `a` (the bottom row) → new lands directly below it.
        assert!(server.place_live_session_after(&new, Some(&a)));
        assert_eq!(server.live_session_order, vec![b.clone(), a.clone(), new.clone()]);

        // Unresolvable anchor → fails open, order untouched.
        assert!(!server.place_live_session_after(&new, Some("/not/a/session")));
        assert!(!server.place_live_session_after(&new, None));
        assert_eq!(server.live_session_order, vec![b, a, new]);
    }

    #[test]
    fn remove_live_session_does_not_fallback_to_stored_session() {
        let tree = SessionNode {
            kind: SessionNodeKind::Group,
            name: "sessions".to_string(),
            title: None,
            document_kind: None,
            group_kind: None,
            path: PathBuf::from("/"),
            children: vec![SessionNode {
                kind: SessionNodeKind::CodexSession,
                name: "saved".to_string(),
                title: Some("Saved".to_string()),
                document_kind: None,
                group_kind: None,
                path: PathBuf::from("/home/pi/.codex/sessions/example.jsonl"),
                children: Vec::new(),
                session_id: Some("saved".to_string()),
                cwd: Some("/home/pi".to_string()),
                ..Default::default()
            }],
            session_id: None,
            cwd: None,
            ..Default::default()
        };
        let mut server = YggtermServer::new(
            &tree,
            false,
            GhosttyHostSupport::shadow("test".to_string(), false, false),
            UiTheme::ZedLight,
        );
        let stored_path = "/home/pi/.codex/sessions/example.jsonl";
        server.sessions.insert(
            stored_path.to_string(),
            build_session(
                SessionKind::Codex,
                stored_path,
                Some("saved"),
                Some("/home/pi"),
                Some("Saved"),
                None,
                server.backend,
                server.theme,
                server.ghostty_host.bridge_enabled,
                StoredPreviewHydrationMode::Deferred,
            ),
        );
        let live_path = server.start_local_session(SessionKind::Shell, Some("/tmp"), Some("Temp"));
        server.active_session_path = Some(live_path.clone());

        assert!(
            server
                .remove_live_session(&live_path)
                .expect("remove live local session")
        );
        assert_eq!(server.active_session_path(), None);
        assert!(server.sessions.contains_key(stored_path));
        assert!(!server.sessions.contains_key(&live_path));
    }

    #[test]
    fn detach_live_session_view_preserves_keep_alive_runtime_metadata() {
        let tree = SessionNode {
            kind: SessionNodeKind::Group,
            name: "sessions".to_string(),
            title: None,
            document_kind: None,
            group_kind: None,
            path: PathBuf::from("/"),
            children: Vec::new(),
            session_id: None,
            cwd: None,
            ..Default::default()
        };
        let mut server = YggtermServer::new(
            &tree,
            false,
            GhosttyHostSupport::shadow("test".to_string(), false, false),
            UiTheme::ZedLight,
        );
        let live_path =
            server.start_local_session(SessionKind::Shell, Some("/tmp/kept"), Some("Kept"));
        server
            .set_live_session_keep_alive(&live_path, true)
            .expect("mark keep alive");
        server.active_session_path = Some(live_path.clone());
        server.active_view_mode = WorkspaceViewMode::Terminal;

        assert!(
            server
                .detach_live_session_view(&live_path)
                .expect("detach kept live session")
        );

        assert_eq!(server.active_session_path(), None);
        assert_eq!(server.active_view_mode(), WorkspaceViewMode::Rendered);
        assert!(
            server.sessions.contains_key(&live_path),
            "ordinary close of a kept session must not remove its live metadata"
        );
        assert!(
            server
                .live_session_order
                .iter()
                .any(|path| path == &live_path),
            "ordinary close of a kept session must keep the row in Live Sessions"
        );
        assert!(server.live_session_keep_alive(&live_path));
    }

    #[test]
    fn remove_live_session_clears_active_path_for_normalized_active_alias() {
        let tree = SessionNode {
            kind: SessionNodeKind::Group,
            name: "sessions".to_string(),
            title: None,
            document_kind: None,
            group_kind: None,
            path: PathBuf::from("/"),
            children: Vec::new(),
            session_id: None,
            cwd: None,
            ..Default::default()
        };
        let mut server = YggtermServer::new(
            &tree,
            false,
            GhosttyHostSupport::shadow("test".to_string(), false, false),
            UiTheme::ZedLight,
        );
        let removed_key =
            server.start_local_session(SessionKind::Shell, Some("/tmp/remove"), Some("Remove"));
        let survivor_key =
            server.start_local_session(SessionKind::Shell, Some("/tmp/keep"), Some("Keep"));
        let removed_path = server
            .sessions
            .get(&removed_key)
            .expect("removed session")
            .session_path
            .clone();
        server.active_session_path = Some(removed_path.clone());

        assert!(
            server
                .remove_live_session(&removed_path)
                .expect("remove live local session")
        );

        assert_eq!(server.active_session_path(), None);
        assert_eq!(server.active_view_mode(), WorkspaceViewMode::Rendered);
        assert!(!server.sessions.contains_key(&removed_key));
        assert!(
            !server
                .live_session_order
                .iter()
                .any(|path| path == &removed_key || path == &removed_path)
        );
        assert!(
            server.sessions.contains_key(&survivor_key),
            "the daemon may keep other live runtimes, but close-time viewport fallback belongs to the GUI history"
        );
    }

